window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q04"]=window.__LIBQ["pham-nhan-tu-tien"]["q04"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q04"]["map"]={"updatedAt":"2026-07-13","count":192,"nodes":[{"id":"thach-dong-chua-truyen-tong-tran","name":"Thạch động chứa Truyền tống trận","cn":"","capDo":"khac","parentId":"co-dao","blurb":"Thạch động tối tăm nơi Hàn Lập và Khúc Hồn xuất hiện sau truyền tống.","detail":"Đây là nơi đặt Truyền Tống trận cổ xưa ở điểm đến. Thạch động không có người, tối, đầy bụi và mùi ẩm mốc, có thạch môn dẫn ra cầu thang đá lên mặt đất.","theLucLienQuan":[],"nguon":["@c0364"]},{"id":"cau-thang-da-mau-xanh","name":"Cầu thang đá màu xanh","cn":"","capDo":"khac","parentId":"thach-dong-chua-truyen-tong-tran","blurb":"Lối đi phủ bụi nối thạch động chứa Truyền Tống trận với mặt đất.","detail":"Cầu thang đá màu xanh dẫn từ thạch động lên trên. Lối đi phủ bụi dày và kết thúc ở cửa ra bị đá núi chắn kín.","theLucLienQuan":[],"nguon":["@c0364"]},{"id":"dai-hai-xa-la","name":"Đại hải xa lạ","cn":"","capDo":"vuc","parentId":null,"blurb":"Vùng biển xanh vô tận nơi Hàn Lập xuất hiện sau khi rời Thiên Nam.","detail":"Sau khi ra khỏi lối đá, Hàn Lập nhìn thấy vùng nước xanh mênh mông cùng không khí ẩm mặn. Màu nước không giống ghi chép về Vô Biên Hải, khiến hắn suy đoán mình đã bị truyền khỏi Thiên Nam đến một bờ biển xa lạ.","theLucLienQuan":[],"nguon":["@c0364"]},{"id":"co-dao","name":"Cô đảo","cn":"","capDo":"khac","parentId":"dai-hai-xa-la","blurb":"Hòn đảo đơn độc nơi đặt điểm đến của Truyền Tống trận cổ xưa.","detail":"Cô đảo có phạm vi khoảng mười dặm, có núi đá nhỏ chứa lối ra từ thạch động truyền tống. Xung quanh chỉ thấy biển, không thấy bờ hay đảo khác, linh khí trên đảo thấp, chỉ có đá, cây cối và rắn nhỏ.","theLucLienQuan":[],"nguon":["@c0364"]},{"id":"hai-thuyen-lon-tren-mat-bien","name":"Hải thuyền lớn trên mặt biển","cn":"","capDo":"khac","parentId":"dai-hai-xa-la","blurb":"Con thuyền lớn kỳ lạ mà Hàn Lập gặp sau khi rời cô đảo.","detail":"Hải thuyền rất lớn nhưng không có cột buồm hay cánh buồm. Ở đầu thuyền có hơn mười con cá khổng lồ không có linh khí kéo thuyền đi tới, nên Hàn Lập mới dám áp sát.","theLucLienQuan":[],"nguon":["@c0364"]},{"id":"loan-tinh-hai","name":"Loạn Tinh Hải","cn":"乱星海","capDo":"vuc","parentId":null,"blurb":"Loạn Tinh Hải là hải vực mới nơi Hàn Lập đặt chân sau khi rời Thiên Nam. Chương này xác định vị trí hiện tại của hắn nằm giáp phía tây nam Loạn Tinh Hải.","detail":"Loạn Tinh Hải là vùng biển rộng có nhiều đảo lớn nhỏ, nơi tiên sư và phàm nhân cùng sinh sống. Vương Trường Thanh giới thiệu cho Hàn Lập rằng khu vực hiện tại thuộc vùng giáp tây nam Loạn Tinh Hải, mở ra bản đồ tu tiên hoàn toàn khác với Thiên Nam.","theLucLienQuan":["Quy chế đảo chủ Loạn Tinh Hải"],"nguon":["@c0365","@c0406","@c0472","@c0490"]},{"id":"tay-nam-loan-tinh-hai","name":"Tây nam Loạn Tinh Hải","cn":"","capDo":"vuc","parentId":"loan-tinh-hai","blurb":"Tây nam Loạn Tinh Hải là vùng biển nơi hải thuyền của Cố đông chủ xuất hiện và nơi Hàn Lập bắt đầu tìm hiểu thế giới mới. Phụ cận vùng này có Vĩ Tinh đảo, Khôi Tinh Đảo và Tang Tinh.","detail":"Theo lời Vương Trường Thanh, khu vực hiện tại giáp phía tây nam Loạn Tinh Hải. Đây là vùng có ba đảo lớn cùng nhiều đảo vừa và nhỏ, nơi tồn tại tập tục đảo chủ quản lý tu sĩ bằng chức vụ và linh thạch.","theLucLienQuan":["Khôi Tinh Đảo","Quy chế đảo chủ Loạn Tinh Hải"],"nguon":["@c0365"]},{"id":"vi-tinh-dao","name":"Vĩ Tinh đảo","cn":"","capDo":"khac","parentId":"tay-nam-loan-tinh-hai","blurb":"Vĩ Tinh đảo là một trong ba đảo lớn phụ cận vùng tây nam Loạn Tinh Hải.","detail":"Vương Trường Thanh nêu Vĩ Tinh đảo cùng Khôi Tinh Đảo và Tang Tinh là ba hòn đảo lớn quanh khu vực hải thuyền đang đi qua.","theLucLienQuan":[],"nguon":["@c0365"]},{"id":"khoi-tinh-dao","name":"Khôi Tinh Đảo","cn":"","capDo":"khac","parentId":"tay-nam-loan-tinh-hai","blurb":"Khôi Tinh Đảo là đảo mà Cố đông chủ muốn mời Hàn Lập đến cư trú. Nó cũng là một trong ba đảo lớn phụ cận vùng tây nam Loạn Tinh Hải.","detail":"Khôi Tinh Đảo được nhắc đến vừa như nơi Cố đông chủ có liên hệ, vừa như một trong ba đảo lớn quanh vùng biển hiện tại. Hàn Lập chưa nhận lời đến ngay mà chỉ tạm ở lại hải thuyền vài ngày để học ngôn ngữ và tìm hiểu tình hình.","theLucLienQuan":["Khôi Tinh Đảo"],"nguon":["@c0365"]},{"id":"tang-tinh","name":"Tang Tinh","cn":"","capDo":"khac","parentId":"tay-nam-loan-tinh-hai","blurb":"Tang Tinh là một trong ba đảo lớn phụ cận vùng tây nam Loạn Tinh Hải.","detail":"Tang Tinh được Vương Trường Thanh nhắc cùng Vĩ Tinh đảo và Khôi Tinh Đảo khi giới thiệu cho Hàn Lập về các đảo lớn trong vùng phụ cận.","theLucLienQuan":[],"nguon":["@c0365"]},{"id":"that-tinh-hai","name":"Thất Tinh Hải","cn":"","capDo":"vuc","parentId":"loan-tinh-hai","blurb":"Hải vực có nhiều đảo trong Loạn Tinh Hải, nơi phàm nhân sống dựa vào đảo và thuyền buôn. Vùng này nổi tiếng với tam đại thiên tai gồm Yêu thú, Thiên phong và Quỷ vụ.","detail":"Thất Tinh Hải là vùng biển có các đảo nhỏ được tiên sư bố trí tiên thuật để phòng hộ yêu thú và Thiên phong. Phàm nhân đi xa trên biển thường mời tu sĩ tự do đi theo thuyền để tăng cơ hội sống sót. Tam đại thiên tai của vùng gồm Yêu thú, Thiên phong và Quỷ vụ; trong đó Thiên phong có thể cuốn cả tiên sư vào hiểm cảnh, còn Quỷ vụ là sương đen lang thang khiến vật sống bị vây vào chưa từng trở ra.","theLucLienQuan":["Khôi Tinh Đảo"],"nguon":["@c0366"]},{"id":"cang-khau-khoi-tinh-dao","name":"Cảng khẩu Khôi Tinh Đảo","cn":"","capDo":"khac","parentId":"khoi-tinh-dao","blurb":"Bến cảng lớn của Khôi Tinh Đảo, nơi hải thuyền của Cố đông chủ cập bến.","detail":"Cảng khẩu Khôi Tinh Đảo lớn hơn hẳn bến tàu mà Hàn Lập từng thấy ở Thiên Nam, có nhiều cự thuyền cỡ thuyền Cố đông chủ, hàng trăm thuyền lớn nhỏ và người qua lại đông đúc. Tu tiên giả lạ đến đảo phải thông tri cảng khẩu để tránh bị coi là kẻ xâm nhập ác ý.","theLucLienQuan":["Khôi Tinh Đảo","Cố gia"],"nguon":["@c0367"]},{"id":"thach-oc-ben-canh-cang-khau","name":"Thạch ốc bên cạnh cảng khẩu","cn":"","capDo":"khac","parentId":"cang-khau-khoi-tinh-dao","blurb":"Thạch ốc đơn giản ở cạnh cảng khẩu Khôi Tinh Đảo. Đây là nơi Dương tiên sư phụ trách thủ tục và cấp ngọc bài cho Hàn Lập.","detail":"Trong thạch ốc chỉ có bàn gỗ, ghế dựa và Dương tiên sư ngồi dưỡng thần. Cố đông chủ đưa Hàn Lập tới đây, nộp linh thạch, để Hàn Lập nhận ngọc bài màu xanh làm thẻ thân phận.","theLucLienQuan":["Khôi Tinh Đảo"],"nguon":["@c0368"]},{"id":"co-gia-trang","name":"Cố gia trang","cn":"","aliases":["Nông trang Cố gia"],"capDo":"khac","parentId":"khoi-tinh-dao","blurb":"Trang viên của Cố gia trên Khôi Tinh Đảo, rộng hơn mười mẫu và có trạch viện mới xây. Quanh tòa nhà có các cây tùng bị hạ cấm chế đủ vây khốn tu tiên giả cấp thấp.","detail":"Cố gia trang có cây trồng lạ, nông phu làm việc, tùng xanh, tường đất cao và cự trạch trung tâm. Hàn Lập phát hiện khí tượng trận pháp trên các cây tùng quanh tòa nhà, sau đó từ chối ở trong nhà và chọn ngọn đồi gần đó để tạm trú.","theLucLienQuan":["Cố gia"],"nguon":["@c0368"]},{"id":"ngon-doi-canh-co-gia","name":"Ngọn đồi cạnh Cố gia","cn":"","capDo":"khac","parentId":"co-gia-trang","blurb":"Ngọn đồi gần Cố gia trang nơi Hàn Lập chọn tạm trú. Tại đây hắn dựng mộc ốc và tu luyện một tháng để khôi phục tu vi.","detail":"Sau khi từ chối vào trạch viện Cố gia, Hàn Lập chỉ về ngọn đồi gần đó rồi cùng Khúc Hồn lên núi. Hắn chọn đất lưng chừng núi, dùng pháp khí chặt tùng, để Khúc Hồn làm việc và dựng một mộc ốc đơn giản.","theLucLienQuan":["Cố gia"],"nguon":["@c0368"]},{"id":"moc-oc-tren-doi","name":"Mộc ốc trên đồi","cn":"","capDo":"khac","parentId":"ngon-doi-canh-co-gia","blurb":"Nhà gỗ đơn giản do Hàn Lập và Khúc Hồn dựng trên ngọn đồi cạnh Cố gia. Nó trở thành nơi Hàn Lập phục đan, dụng dược và luyện khí đả tọa trong một tháng.","detail":"Mộc ốc được dựng trong khoảng nửa canh giờ bằng gỗ tùng trên đồi, có bàn ghế và giường gỗ đơn giản. Hàn Lập ở đây tu luyện cho đến khi khôi phục tới Luyện khí kỳ tầng năm.","theLucLienQuan":["Cố gia"],"nguon":["@c0368"]},{"id":"thanh-thi-da-trang-tren-khoi-tinh-dao","name":"Thành thị đá trắng trên Khôi Tinh Đảo","cn":"","capDo":"thanh","parentId":"khoi-tinh-dao","blurb":"Thành thị xây bằng đá trắng trên Khôi Tinh Đảo. Cửa thành có vệ binh phàm nhân kiểm tra lệnh bài và dùng vòng đồng nhận biết tu tiên giả.","detail":"Hàn Lập theo Cố đông chủ và Vương Trường Thanh đi thú xa hai canh giờ tới thành thị đá trắng. Người vào thành phải trình lệnh bài; khi Hàn Lập được vòng đồng kiểm tra và phát lục quang, vệ binh liền hành lễ cung kính.","theLucLienQuan":["Khôi Tinh Đảo"],"nguon":["@c0368"]},{"id":"dong-thach-thanh","name":"Đông Thạch thành","cn":"","capDo":"thanh","parentId":"khoi-tinh-dao","blurb":"Đông Thạch thành là thành bạch thạch trên Khôi Tinh Đảo, nơi Hàn Lập theo Cố đông chủ đi qua trong ngày mở cửa. Lượng người trong thành đông hơn trước nhiều lần vì các thành trấn đông bộ tụ hội giao dịch.","detail":"Đường phố bạch thạch của Đông Thạch thành trở nên đông đúc trong ngày Khôi Tinh Đảo ba tháng mở cửa một lần. Từ đây, thú xa chở Hàn Lập và Cố đông chủ đi tới quảng trường trung tâm để vào cung điện khiêu chiến.","theLucLienQuan":["Khôi Tinh Đảo","Cố gia"],"nguon":["@c0369"]},{"id":"quang-truong-trung-tam-dong-thach-thanh","name":"Quảng trường trung tâm Đông Thạch thành","cn":"","capDo":"khac","parentId":"dong-thach-thanh","blurb":"Quảng trường trung tâm Đông Thạch thành rộng hơn mười mẫu, tấp nập người qua lại trong ngày Khôi Tinh Đảo mở cửa. Nơi đây có cửa hiệu và gian hàng tạm thời phục vụ giao dịch vật phẩm hiếm.","detail":"Hàn Lập theo Cố đông chủ tới quảng trường sau khi đi qua đường phố đông đúc. Quảng trường là điểm tụ hội của người từ các thành trấn đông bộ, đồng thời nằm cạnh cung điện trung tâm tổ chức vòng khiêu chiến.","theLucLienQuan":["Khôi Tinh Đảo"],"nguon":["@c0369"]},{"id":"cung-dien-trung-tam","name":"Cung điện trung tâm","cn":"","capDo":"khac","parentId":"quang-truong-trung-tam-dong-thach-thanh","blurb":"Cung điện trung tâm là tòa kiến trúc cao vài chục trượng cạnh quảng trường Đông Thạch thành. Bên trong có khu dành cho tu sĩ tham gia vòng khiêu chiến.","detail":"Cung điện có vệ binh canh giữ, Cố đông chủ phải giao thiệp mới đưa Hàn Lập vào được. Sau đó chỉ người tu tiên tham gia khiêu chiến được đi tiếp, dẫn tới khu đại sảnh và sàn đấu phía sau.","theLucLienQuan":["Khôi Tinh Đảo","Mười thương gia","Cố gia"],"nguon":["@c0369"]},{"id":"dai-sanh-hinh-vong-tron","name":"Đại sảnh hình vòng tròn","cn":"","capDo":"khac","parentId":"cung-dien-trung-tam","blurb":"Đại sảnh hình vòng tròn là nơi hơn ba mươi tu sĩ Luyện khí kỳ tập trung trong vòng khiêu chiến. Lão giả Trúc Cơ sơ kỳ tại đây công bố luật và cho rút thẻ ghép cặp.","detail":"Hàn Lập được Văn Tường dẫn vào đại sảnh sau khi qua cửa gỗ. Tại đây, các tu sĩ rút thẻ từ ống ngọc màu xanh, một số dùng thần thức dò xét bị thanh quang phản chấn, rồi lần lượt ra sàn đấu.","theLucLienQuan":["Khôi Tinh Đảo","Mười thương gia"],"nguon":["@c0369"]},{"id":"san-dau-lo-thien","name":"Sàn đấu lộ thiên","cn":"","capDo":"khac","parentId":"cung-dien-trung-tam","blurb":"Sàn đấu lộ thiên là khu tỷ thí phía sau đại sảnh hình vòng tròn, được trận pháp bảo vệ. Khi Hàn Lập và đối thủ bước vào, họ xuất hiện trong một vùng thiên địa màu trắng có sương mù bao quanh.","detail":"Sàn đấu được nói là có trận pháp mạnh nên không sợ pháp thuật phá hư. Đây là nơi các cặp tu sĩ trong vòng rút thẻ phân thắng bại, trong đó Hàn Lập vào trận số bảy với trung niên tu sĩ Luyện khí tầng bảy.","theLucLienQuan":["Khôi Tinh Đảo","Mười thương gia"],"nguon":["@c0369"]},{"id":"dang-tien-cac","name":"Đăng Tiên Các","cn":"","capDo":"khac","parentId":"tien-son-trung-bo-khoi-tinh-dao","blurb":"Địa điểm trên tiên sơn dùng để xử lý tư cách ở lại Khôi Tinh Đảo lâu dài. Hàn Lập được báo có thể tới đây để giải quyết thủ tục định cư và chọn nơi tu luyện về sau.","detail":"Đăng Tiên Các nằm trên tiên sơn trung bộ Khôi Tinh Đảo, là nơi tu tiên giả làm thủ tục có được tư cách ở lại Khôi Tinh Đảo vĩnh cửu và xác định chỗ tu luyện sau này.","theLucLienQuan":["Khôi Tinh Đảo"],"nguon":["@c0370","@c0371"]},{"id":"tien-son-trung-bo-khoi-tinh-dao","name":"Tiên sơn trung bộ Khôi Tinh Đảo","cn":"","capDo":"khac","parentId":"khoi-tinh-dao","blurb":"Cự sơn màu xanh ở trung bộ Khôi Tinh Đảo, có ba ngọn lớn cao chọc trời như pháo đài nguy nga. Hàn Lập bay tới đây trên đường đến Đăng Tiên Các và gặp Văn Tường.","detail":"Tiên sơn là vùng núi lớn ở trung bộ Khôi Tinh Đảo, xung quanh có nhiều núi nhỏ không đếm xuể, ba đỉnh lớn vươn cao vào mây. Đây là nơi đặt Đăng Tiên Các, địa điểm xử lý tư cách ở lại lâu dài cho tu tiên giả.","theLucLienQuan":["Khôi Tinh Đảo"],"nguon":["@c0370"]},{"id":"san-dau-trong-bach-quang","name":"Sàn đấu trong bạch quang","cn":"","capDo":"khac","parentId":"dai-sanh-hinh-vong-tron","blurb":"Không gian giao đấu được bạch quang bao phủ trong đại sảnh tỷ thí. Các cặp tu sĩ bước vào đây rồi người thắng kẻ bại lần lượt đi ra.","detail":"Sàn đấu trong bạch quang là nơi diễn ra các trận khiêu chiến ở đại sảnh. Hàn Lập lần lượt kéo trung niên tu sĩ và hán tử khỏe mạnh bị đánh bại ra khỏi khu vực này.","theLucLienQuan":["Khôi Tinh Đảo"],"nguon":["@c0370"]},{"id":"thanh-van-son","name":"Thanh Vân Sơn","cn":"","capDo":"vuc","parentId":"khoi-tinh-dao","blurb":"Thanh Vân Sơn là khu núi lớn trên Khôi Tinh Đảo, nơi tu sĩ chọn động phủ và nơi tu luyện. Khu vực này có ba đại cự phong, nhiều tiểu sơn, động quật và sơn cốc.","detail":"Theo lời Văn Tường, Thanh Vân Sơn có ba đại cự phong, ba trăm sáu mươi bảy tiểu sơn cùng hơn ngàn động quật, sơn cốc. Tu sĩ Trúc Cơ kỳ thường có thể chọn một ngọn núi riêng, còn tu sĩ Luyện Khí kỳ chủ yếu chọn động quật hoặc sơn cốc; ba mươi sáu ngọn núi linh khí tốt nhất là đối tượng khiêu chiến mười năm một lần.","theLucLienQuan":["Khôi Tinh Đảo"],"nguon":["@c0371"]},{"id":"thien-tru-phong","name":"Thiên Trụ Phong","cn":"","capDo":"khac","parentId":"thanh-van-son","blurb":"Thiên Trụ Phong là chủ phong cao nhất của Thanh Vân Sơn và là linh nhãn của Khôi Tinh Đảo. Đây là nơi tu luyện của đảo chủ Mộc Long chân nhân, tu sĩ khác không được phép tiến vào.","detail":"Thiên Trụ Phong được Văn Tường giới thiệu là đỉnh cao nhất trong ba đại cự phong, nơi có linh khí tốt nhất vì là linh nhãn của đảo. Đỉnh này thuộc về đảo chủ Mộc Long chân nhân, tu sĩ Kết Đan trung kỳ.","theLucLienQuan":["Khôi Tinh Đảo"],"nguon":["@c0371"]},{"id":"thien-tieu-phong","name":"Thiên Tiêu Phong","cn":"","capDo":"khac","parentId":"thanh-van-son","blurb":"Thiên Tiêu Phong là một trong ba đại cự phong của Thanh Vân Sơn. Đây là một trong hai động phủ của hai phó đảo chủ Viên Quân chân nhân và Khản Cầm chân nhân.","detail":"Thiên Tiêu Phong cùng Thiên Môn Phong được nêu là nơi đặt động phủ của hai phó đảo chủ Khôi Tinh Đảo. Linh khí tại hai chủ phong này cao hơn nhiều nơi khác trên Thanh Vân Sơn.","theLucLienQuan":["Khôi Tinh Đảo"],"nguon":["@c0371"]},{"id":"thien-mon-phong","name":"Thiên Môn Phong","cn":"","capDo":"khac","parentId":"thanh-van-son","blurb":"Thiên Môn Phong là một trong ba đại cự phong của Thanh Vân Sơn. Đây là một trong hai động phủ của hai phó đảo chủ Viên Quân chân nhân và Khản Cầm chân nhân.","detail":"Thiên Môn Phong cùng Thiên Tiêu Phong được Văn Tường nhắc là hai chủ phong còn lại ngoài Thiên Trụ Phong. Hai phó đảo chủ Khôi Tinh Đảo là Viên Quân chân nhân và Khản Cầm chân nhân tu luyện tại hai nơi này.","theLucLienQuan":["Khôi Tinh Đảo"],"nguon":["@c0371"]},{"id":"ba-muoi-sau-ngon-nui-cao-nhat-thanh-van-son","name":"Ba mươi sáu ngọn núi cao nhất Thanh Vân Sơn","cn":"","capDo":"khac","parentId":"thanh-van-son","blurb":"Ba mươi sáu ngọn núi cao nhất Thanh Vân Sơn là nhóm đỉnh núi có linh khí sung túc nhất sau ba chủ phong. Chúng là mục tiêu tranh đoạt trong kỳ khiêu chiến mười năm một lần.","detail":"Ngoài ba đại cự phong, ba mươi sáu ngọn núi cao nhất trên Thanh Vân Sơn có linh khí tốt nhất nên trở thành đối tượng khiêu chiến định kỳ. Người thắng có thể giành quyền làm chủ nơi tu luyện tốt hơn.","theLucLienQuan":["Khôi Tinh Đảo"],"nguon":["@c0371"]},{"id":"tieu-hoan-dao","name":"Tiểu Hoàn Đảo","cn":"","capDo":"khac","parentId":"khoi-tinh-dao","blurb":"Đảo phụ nằm ngoài Khôi Tinh Đảo, dài khoảng sáu bảy mươi dặm. Hàn Lập chọn nơi này làm chỗ tu luyện để tránh xa tu sĩ khác.","detail":"Tiểu Hoàn Đảo có vài tiểu linh mạch nhưng linh khí rất yếu, diện tích nhỏ, có trận pháp phòng hộ và một trấn nhỏ vài trăm dân. Người chọn đảo phải tự gánh linh thạch duy trì trận pháp, đổi lại gần như trở thành đảo chủ trên thực tế và không phải nộp cống thuế hằng năm cho chủ đảo.","theLucLienQuan":["Khôi Tinh Đảo","Cư dân Tiểu Hoàn Đảo","Hàn Lập"],"nguon":["@c0372"]},{"id":"khoi-tinh-thanh","name":"Khôi Tinh Thành","cn":"","capDo":"thanh","parentId":"khoi-tinh-dao","blurb":"Thành thị lớn nhất trên Khôi Tinh Đảo theo lời Vương Trường Thanh. Nơi này có Thiên đô nhai chuyên giao dịch vật phẩm tu tiên.","detail":"Hàn Lập biết Khôi Tinh Thành có khu giao dịch cho người tu tiên và từng muốn đến xem. Tuy nhiên vì tu vi hiện tại quá thấp, hắn từ bỏ ý định vào thành giao dịch.","theLucLienQuan":["Khôi Tinh Đảo"],"nguon":["@c0372"]},{"id":"thien-do-nhai","name":"Thiên đô nhai","cn":"","capDo":"khac","parentId":"khoi-tinh-thanh","blurb":"Khu giao dịch vật phẩm tu tiên trong Khôi Tinh Thành. Hàn Lập tạm thời không tới vì cảnh giác trước tu vi thấp của mình.","detail":"Thiên đô nhai được Vương Trường Thanh nhắc đến như nơi chuyên mua bán giao dịch vật phẩm cho người tu tiên. Hàn Lập muốn xem công pháp và vật phẩm hải ngoại nhưng quyết định tránh đi để giữ an toàn.","theLucLienQuan":["Khôi Tinh Đảo"],"nguon":["@c0372","@c0445"]},{"id":"ben-tau-tieu-hoan-dao","name":"Bến tàu Tiểu Hoàn Đảo","cn":"","capDo":"khac","parentId":"tieu-hoan-dao","blurb":"Bến tàu nơi có cửa vào trận pháp của Tiểu Hoàn Đảo. Hàn Lập và Khúc Hồn hạ xuống tại đây và gặp Hắc Quý cùng nhóm ngư dân.","detail":"Sau một ngày một đêm bay từ Khôi Tinh Đảo, Hàn Lập tìm được lối vào trận pháp tại khu bến tàu. Đây là nơi hắn xác nhận đảo, gặp cư dân đầu tiên và công bố từ nay linh thạch tiêu hao trên đảo do mình bỏ ra.","theLucLienQuan":["Cư dân Tiểu Hoàn Đảo","Hàn Lập"],"nguon":["@c0372"]},{"id":"tieu-hoan-son","name":"Tiểu Hoàn Sơn","cn":"","capDo":"khac","parentId":"tieu-hoan-dao","blurb":"Tiểu Hoàn Sơn là tiểu sơn mạch phía tây hòn đảo Hàn Lập quản lý. Nơi này có hai ngọn núi được hắn chọn để lập hệ động phủ thật giả.","detail":"Tiểu Hoàn Sơn nằm cách khu dân cư trên đảo hơn hai mươi dặm về phía tây. Hàn Lập cảm nhận được linh khí nhàn nhạt tại đây, rồi chọn núi thấp làm động phủ ngoài và núi cao hơn làm động phủ thật để tu luyện, trồng linh thảo và nuôi trùng.","theLucLienQuan":[],"nguon":["@c0373"]},{"id":"tran-nho-tren-tieu-hoan-dao","name":"Trấn nhỏ trên đảo","cn":"","capDo":"khac","parentId":"tieu-hoan-dao","blurb":"Trấn nhỏ duy nhất trên hòn đảo Hàn Lập quản lý. Trưởng trấn tại đây tiếp Hàn Lập, kiểm tra kim sắc ngọc giản và nhận linh thạch duy trì phòng hộ trận.","detail":"Trấn nhỏ nằm gần cảng khẩu trên đảo, là khu dân cư duy nhất được nhắc tới trong chương. Khi Hàn Lập và Khúc Hồn đến, trưởng trấn đại diện cư dân tiếp nhận quyền điều khiển của tiên sư và nhận linh thạch đủ dùng cho phòng hộ trận trong một năm.","theLucLienQuan":["Cư dân Tiểu Hoàn Đảo"],"nguon":["@c0373"]},{"id":"ngon-nui-thap-trong-tieu-hoan-son","name":"Ngọn núi thấp trong Tiểu Hoàn Sơn","cn":"","capDo":"khac","parentId":"tieu-hoan-son","blurb":"Ngọn núi thấp có động phủ cũ của tu sĩ trước để lại. Hàn Lập dùng nơi này làm lớp động phủ giả và bố trí Điên Đảo Ngũ Hành Trận gần đó.","detail":"Ngọn núi thấp trong Tiểu Hoàn Sơn có sẵn động phủ cũ đầy đủ, không tổn hao. Hàn Lập giữ nó làm mặt ngoài để che mắt, đồng thời đào thông đạo ngầm nối sang ngọn núi cao hơn nơi đặt động phủ thật.","theLucLienQuan":[],"nguon":["@c0373"]},{"id":"ngon-nui-cao-trong-tieu-hoan-son","name":"Ngọn núi cao trong Tiểu Hoàn Sơn","cn":"","capDo":"khac","parentId":"tieu-hoan-son","blurb":"Ngọn núi cao có linh khí sung túc hơn trong Tiểu Hoàn Sơn. Hàn Lập xây động phủ thật bán phong bế tại đây, mô phỏng bố cục động phủ Thái Nhạc Sơn.","detail":"Sau khi khảo sát, Hàn Lập chọn ngọn núi cao hơn làm nơi đặt động phủ thật. Hắn đào thông đạo ngầm từ động phủ cũ sang đây, xây nơi tu luyện và bồi dưỡng linh thảo không có cửa ra vào trực tiếp để tăng mức an toàn.","theLucLienQuan":[],"nguon":["@c0373"]},{"id":"duoc-vien-an-bi","name":"Dược viên ẩn bí","cn":"","capDo":"khac","parentId":"ngon-nui-cao-trong-tieu-hoan-son","blurb":"Dược viên nằm trong động phủ thật của Hàn Lập tại Tiểu Hoàn Sơn. Đây là nơi hắn trồng mầm linh thảo và đặt tiểu bình để ngưng tụ lục dịch.","detail":"Trong động phủ thật, Hàn Lập bố trí khu dược viên kín để bồi dưỡng linh thảo. Tiểu bình được đặt ở một góc dược viên, tiếp tục ngưng tụ lục dịch qua vách động nhằm phục vụ việc trồng linh thảo lâu dài.","theLucLienQuan":[],"nguon":["@c0373"]},{"id":"mat-that-nuoi-trung-tieu-hoan-son","name":"Hơn mười gian mật thất nuôi trùng","cn":"","capDo":"khac","parentId":"ngon-nui-cao-trong-tieu-hoan-son","blurb":"Các mật thất nuôi trùng do Hàn Lập mở trong động phủ mới. Chúng được cải tạo theo Dục Trùng tâm đắc để nuôi Bạch tri thù và kỳ trùng.","detail":"Hàn Lập mở hơn mười mật thất lớn nhỏ khác nhau, cải tạo môi trường bên trong theo Dục Trùng tâm đắc của tu sĩ Ngự Linh Tông. Sau đó hắn đưa Bạch tri thù và kỳ trùng còn sống vào, đặt cấm chế ngăn bỏ chạy và chuẩn bị trùng thực.","theLucLienQuan":["Ngự Linh Tông"],"nguon":["@c0373"]},{"id":"thai-nhac-son","name":"Thái Nhạc Sơn","cn":"","capDo":"khac","parentId":null,"blurb":"Thái Nhạc Sơn được nhắc như mẫu động phủ cũ để Hàn Lập mô phỏng khi xây động phủ thật tại Tiểu Hoàn Sơn. Đây là mốc ký ức về nơi tu luyện trước kia của hắn.","detail":"Khi xây động phủ mới trong ngọn núi cao tại Tiểu Hoàn Sơn, Hàn Lập mô phỏng theo động phủ ở Thái Nhạc Sơn. Chi tiết này cho thấy hắn tái lập bố cục quen thuộc để phục vụ tu luyện, dược viên và các khu chức năng trong căn cứ mới.","theLucLienQuan":[],"nguon":["@c0373"]},{"id":"mat-that-luyen-cong","name":"Mật thất luyện công","cn":"","capDo":"khac","parentId":"dong-phu-han-lap","blurb":"Mật thất luyện công là nơi Hàn Lập và Khúc Hồn ngồi đối diện để tế luyện Thân ngoại hóa thân. Thạch môn đóng hơn một tháng trước khi việc tế luyện hoàn tất.","detail":"Trong động phủ trên Tiểu Hoàn Đảo, Hàn Lập bố trí Khúc Hồn trong mật thất, thi pháp đưa quang đoàn xanh vào thân thể Khúc Hồn và dùng bạch quang từ hai mắt liên kết. Nơi này trở thành địa điểm hoàn thành việc tế luyện phân thân sau hơn một tháng.","theLucLienQuan":["Hàn Lập"],"nguon":["@c0374"]},{"id":"hai-ngon-nui-bi-bach-vu-che-dau","name":"Hai ngọn núi bị bạch vụ che dấu","cn":"","capDo":"khac","parentId":"tieu-hoan-dao","blurb":"Hai ngọn núi quanh động phủ Hàn Lập bị bạch vụ và trận pháp bao phủ. Phàm nhân đi vào dễ lạc hướng, phải gọi Hàn tiên sư mới có đường thoát.","detail":"Trong hơn hai mươi năm Hàn Lập bế quan, khu vực hai ngọn núi dần trở thành nơi dân đảo quen tránh xa. Bạch vụ vừa che phủ nơi tu luyện của Hàn Lập vừa giữ khoảng cách giữa động phủ và sinh hoạt phàm nhân trên đảo.","theLucLienQuan":["Hàn Lập","Cư dân trấn Tiểu Hoàn Đảo"],"nguon":["@c0374"]},{"id":"thai-ha-son","name":"Thải Hà sơn","cn":"","capDo":"khac","parentId":null,"blurb":"Thải Hà sơn là địa danh trong quá khứ được Hàn Lập nhớ lại trước lúc tế luyện Khúc Hồn thành thân ngoại hóa thân. Nó gắn với ký ức cũ của hắn khi còn ở Thất Huyền môn.","detail":"Khi nhìn khuôn mặt Khúc Hồn trước khi thi pháp, Hàn Lập nhớ lại Thất Huyền môn, Thải Hà sơn và những bóng hình cũ, khiến địa danh này hiện lên như một mảnh ký ức quá khứ của hắn.","theLucLienQuan":["Thất Huyền môn"],"nguon":["@c0374"]},{"id":"van-mong-cac","name":"Vân Mộng Các","cn":null,"capDo":"khac","parentId":"thien-do-nhai","blurb":"Lầu các xanh biếc lơ lửng giữa Thiên Đô Nhai, cách mặt đất khoảng ba mươi trượng. Cảnh tượng của nó khiến Hàn Lập lần đầu nhìn thấy cũng phải giật mình.","detail":"Toàn thân lầu các xanh biếc như một khối phỉ thúy lớn, lại treo lơ lửng giữa khu giao dịch tu sĩ của Khôi Tinh Thành, là cảnh quan nổi bật nhất trong tầm mắt Hàn Lập khi tới Thiên Đô Nhai.","theLucLienQuan":[],"nguon":["@c0375"]},{"id":"quang-truong-trung-tam-thien-do-nhai","name":"Quảng trường trung tâm Thiên Đô Nhai","cn":"","capDo":"khac","parentId":"thien-do-nhai","blurb":"Quảng trường trung tâm Thiên Đô Nhai là nơi Hàn Lập đi tới sau khi bỏ qua các cửa hàng nhỏ hai bên đường. Giữa quảng trường có Vân Mộng Các lơ lửng, xung quanh là sáu lâu các nhỏ phân bố bốn phía.","detail":"Không gian này được lát bằng ngọc bích bạch khiết, ở giữa không bày vật gì trên mặt đất nhưng phía trên có Vân Mộng Các lơ lửng với đại môn đóng chặt. Sáu lâu các nhỏ như Bạch Thủy Lâu, Ngọc Hoàn Cư và Sơn Hải Các nằm quanh quảng trường, mỗi nơi treo tiêu thức khác nhau để phân loại hàng hóa hoặc chức năng.","theLucLienQuan":["Vân Mộng Các","Bạch Thủy Lâu","Ngọc Hoàn Cư","Sơn Hải Các","Lục Liên Điện"],"nguon":["@c0376"]},{"id":"bach-thuy-lau-map","name":"Bạch Thủy Lâu","cn":"","capDo":"khac","parentId":"quang-truong-trung-tam-thien-do-nhai","blurb":"Bạch Thủy Lâu là lâu các gần Hàn Lập nhất trong sáu lâu các quanh quảng trường trung tâm Thiên Đô Nhai. Bên trong có đại sảnh rộng, nhiều giá bạch ngọc và gần trăm pháp khí bày bán.","detail":"Bạch Thủy Lâu treo tiêu thức thanh tiểu kiếm màu vàng, cho thấy nơi này liên quan đến pháp khí. Hàn Lập vào đây để kiểm chứng suy đoán về các lâu các chuyên môn hóa, sau đó được tiểu nhị mời vào phòng trong vì Khúc Hồn có tu vi Trúc Cơ cao giai.","theLucLienQuan":["Bạch Thủy Lâu","Lục Liên Điện"],"nguon":["@c0376"]},{"id":"ngoc-hoan-cu-map","name":"Ngọc Hoàn Cư","cn":"","capDo":"khac","parentId":"quang-truong-trung-tam-thien-do-nhai","blurb":"Ngọc Hoàn Cư là một trong sáu lâu các tại quảng trường trung tâm Thiên Đô Nhai. Đây là nơi Âu Dương đạo hữu thuộc về và được Tào Lộc liên hệ để đem hai linh vật phụ trợ Kết Đan tới.","detail":"Ngọc Hoàn Cư treo tiêu thức linh chi thảo màu xanh. Dù Hàn Lập không trực tiếp vào nơi này trong chương, địa điểm được nhắc rõ qua việc Tào Lộc truyền tin cho Âu Dương đạo hữu của Ngọc Hoàn Cư để đưa Tuyết Linh Thủy và Thiên Hỏa Dịch sang Bạch Thủy Lâu.","theLucLienQuan":["Ngọc Hoàn Cư","Lục Liên Điện"],"nguon":["@c0376"]},{"id":"thien-nhai-do","name":"Thiên Nhai Đô","cn":"","capDo":"khac","parentId":"khoi-tinh-thanh","blurb":"Khu vực Hàn Lập rời đi sau khi kết thúc việc xem điển tịch và mua Đan đạo bình giám. Từ đây hắn cùng Khúc Hồn bay về hướng Cố Gia Trang.","detail":"Sau khi không còn hứng thú mua thêm điển tịch, Hàn Lập mang Khúc Hồn rời Thiên Nhai Đô. Địa điểm này gắn với đoạn hắn khảo sát đạo thư, phát hiện thủy hệ pháp thuật Loạn Tinh Hải phong phú hơn và mua sách luyện đan để tra Hàng Trần Đan.","theLucLienQuan":[],"nguon":["@c0378"]},{"id":"hai-thuyen-lon-xuat-hai-map","name":"Hải thuyền lớn","cn":"","capDo":"khac","parentId":"cang-khau-khoi-tinh-dao","blurb":"Hải thuyền rời cảng Khôi Tinh Đảo, chở nhóm tiên sư tới địa điểm yêu thú xuất hiện. Bên trong khoang là đại sảnh rộng, sang trọng, nơi Hàn Lập và Khúc Hồn gặp các tu sĩ khác.","detail":"Hải thuyền lớn là phương tiện của chuyến xuất hải sau nửa tháng Hàn Lập quyết định nhận việc. Lạc Chánh làm thuyền trưởng dẫn đường, còn Hàn Lập, Khúc Hồn và các tiên sư khác tập trung trong đại sảnh khoang thuyền trước khi đi đến nơi yêu thú xuất hiện.","theLucLienQuan":["Khôi Tinh Đảo","Lục Liên Điện"],"nguon":["@c0378"]},{"id":"dia-diem-xuat-hien-yeu-thu","name":"Địa điểm xuất hiện yêu thú","cn":"","capDo":"khac","parentId":"loan-tinh-hai","blurb":"Đích đến của chuyến hải thuyền do Lạc Chánh dẫn đường. Đây là nơi nhóm tiên sư được đưa tới vì có yêu thú xuất hiện, liên quan nhiệm vụ Lục Liên Điện dùng Hàng Trần Đan làm thù lao.","detail":"Địa điểm xuất hiện yêu thú được Lạc Chánh nhắc tới khi nghênh tiếp Hàn Lập và Khúc Hồn lên hải thuyền. Chuyến đi nhằm đưa các tiên sư tới nơi này, mở đầu tuyến xuất hải săn yêu thú liên quan Hàng Trần Đan.","theLucLienQuan":["Lục Liên Điện","Khôi Tinh Đảo"],"nguon":["@c0378"]},{"id":"vi-tinh-dao-map","name":"Vĩ Tinh Đảo","cn":"","capDo":"khac","parentId":"loan-tinh-hai","blurb":"Vĩ Tinh Đảo là hòn đảo do Chiêm Thai tiền bối làm đảo chủ. Mao đạo hữu và Tiết đạo hữu được giới thiệu là cao đồ của vị đảo chủ này.","detail":"Trong chuyến săn yêu thú của Lục Liên Điện, Vĩ Tinh Đảo được nhắc qua thân phận của Mao đạo hữu và Tiết đạo hữu, hai tu sĩ cùng được giới thiệu là cao đồ của đảo chủ Chiêm Thai tiền bối.","theLucLienQuan":["Vĩ Tinh Đảo"],"nguon":["@c0379"]},{"id":"kim-miet-dao","name":"Kim Miết Đảo","cn":"","capDo":"khac","parentId":"loan-tinh-hai","blurb":"Kim Miết Đảo là nơi Thanh Toán Tử ẩn tu. Địa danh này được Phùng Tam Nương nhắc khi giới thiệu thân phận lão giả hai mắt trắng.","detail":"Thanh Toán Tử được giới thiệu là ẩn tu Kim Miết Đảo, tu sĩ Trúc Cơ hậu kỳ hệ mộc. Ông tham gia nhóm được Lục Liên Điện mời để chủ trì trận pháp săn yêu thú.","theLucLienQuan":["Thanh Toán Tử"],"nguon":["@c0379"]},{"id":"hoa-minh-dao","name":"Hóa Minh Đảo","cn":"","capDo":"khac","parentId":"loan-tinh-hai","blurb":"Hóa Minh Đảo là nơi xuất thân của vị đại hán đầu bóng lưỡng tham gia chuyến săn yêu thú. Người này ban đầu bế quan trên thuyền vì tu luyện một công pháp lợi hại.","detail":"Trong nhóm tu sĩ được Lục Liên Điện mời, vị tu sĩ đến từ Hóa Minh Đảo xuất hiện muộn sau vài ngày bế quan trên hải thuyền. Hắn có vẻ ngoài hung ác nhưng lời nói cử chỉ hào sảng.","theLucLienQuan":["Đại hán đầu bóng lưỡng ở Hóa Minh Đảo"],"nguon":["@c0379"]},{"id":"hoang-dao-vo-danh","name":"Hoang đảo vô danh","cn":"","capDo":"khac","parentId":"loan-tinh-hai","blurb":"Hoang đảo vô danh là nơi hải thuyền của Lục Liên Điện dừng lại sau một tháng xuất hải. Đại trận bắt yêu thú đã được bố trí tại đây.","detail":"Hòn đảo rộng hơn mười dặm này là điểm đến của đoàn săn yêu thú. Khi nhóm tu sĩ đặt chân lên đảo, Miêu trưởng lão hiện thân, xác nhận đại trận đã được bố trí từ nửa ngày trước và giao nhiệm vụ chủ trì trận pháp cho mọi người.","theLucLienQuan":["Lục Liên Điện"],"nguon":["@c0379"]},{"id":"vung-hai-vuc-phu-can-hoang-dao","name":"Vùng hải vực phụ cận hoang đảo","cn":"","capDo":"khac","parentId":"hoang-dao-vo-danh","blurb":"Vùng hải vực phụ cận hoang đảo là nơi Cổ trưởng lão đang dây dưa truy đuổi yêu thú. Khu vực này liên quan trực tiếp tới kế hoạch dẫn yêu thú vào đại trận.","detail":"Miêu trưởng lão cho biết Cổ trưởng lão đang ở vùng hải vực phụ cận để truy đuổi yêu thú, dự tính sáng sớm hôm sau sẽ dẫn nó tiến vào đại trận đã bố trí trên hoang đảo vô danh.","theLucLienQuan":["Lục Liên Điện"],"nguon":["@c0379"]},{"id":"tieu-dao-vo-danh","name":"Tiểu đảo vô danh","cn":"","capDo":"khac","parentId":"vung-hai-vuc-phu-can-hoang-dao","blurb":"Tiểu đảo vô danh là nơi nhóm tu sĩ nghỉ lại trước khi vào trận săn Anh Lý Thú.","detail":"Phùng Tam Nương đưa nhóm tu sĩ đến đây, qua đêm trước khi sáng hôm sau ra vùng biển cách đảo mười hải lý để chờ yêu thú bị dẫn tới.","theLucLienQuan":["Lục Liên Điện"],"nguon":["@c0380"]},{"id":"vung-bien-cach-dao-muoi-hai-ly","name":"Vùng biển cách đảo mười hải lý","cn":"","capDo":"khac","parentId":"tieu-dao-vo-danh","blurb":"Vùng biển cách đảo mười hải lý là trận địa chờ Anh Lý Thú tiến vào.","detail":"Sáng hôm sau, Phùng Tam Nương dẫn mọi người tới đây. Sáu tu sĩ Trúc Cơ hậu kỳ cầm đại kỳ màu lam đứng thành nửa vòng tròn trên mặt biển để chuẩn bị phong tỏa trận môn.","theLucLienQuan":["Lục Liên Điện"],"nguon":["@c0380"]},{"id":"mat-bien-ngoai-ngan-dam","name":"Mặt biển ngoài ngàn dặm","cn":"","capDo":"khac","parentId":"dai-hai","blurb":"Mặt biển ngoài ngàn dặm là nơi hai tu sĩ Kết Đan bị Anh Lý Thú truy đuổi trước khi về tới trận địa.","detail":"Tại đây, kim quang và hoàng quang của Miêu trưởng lão, Cổ trưởng lão bị khối sương trắng rộng trăm trượng đuổi sát, trong sương vang tiếng trẻ con khóc và tiếng sấm.","theLucLienQuan":["Lục Liên Điện"],"nguon":["@c0380"]},{"id":"dai-hai","name":"Đại hải","cn":"","capDo":"khac","parentId":"loan-tinh-hai","blurb":"Đại hải là môi trường khiến thủy hệ thần thông của Anh Lý Thú phát huy mạnh.","detail":"Trung niên nho sinh nhận định Anh Lý Thú tuy là yêu thú cấp sáu, nhưng trong đại hải tuyệt đối không kém yêu thú cấp bảy vì là thủy hệ linh thú trời sinh.","theLucLienQuan":[],"nguon":["@c0380"]},{"id":"mat-bien-noi-bay-tran-bat-anh-ly-thu","name":"Mặt biển nơi bày trận bắt Anh Lý Thú","cn":"","capDo":"khac","parentId":"dai-hai","blurb":"Khu vực mặt biển diễn ra trận săn Anh Lý Thú. Tại đây nhóm tu sĩ bày trận kỳ màu lam, yêu thú phá trận rồi bị dị bảo chế trụ trước khi âm phong đen bất ngờ trồi lên.","detail":"Đây là không gian chiến đấu chính của chương, nơi trận pháp được giấu sẵn trên mặt biển để chờ Anh Lý Thú lọt vào. Bạch vụ, hào quang màu lam, cơn lốc lớn, Thủy cương thần lôi và âm phong đen lần lượt xuất hiện, khiến cuộc săn yêu chuyển từ vây bắt sang biến cố bất ngờ.","theLucLienQuan":["Lục Liên Điện"],"nguon":["@c0381"]},{"id":"hac-phong","name":"Hắc phong","cn":"","capDo":"khac","parentId":"vung-bien-cach-dao-muoi-hai-ly","blurb":"Hắc phong là khu vực hắc khí gần nơi Anh Lý Thú bị đóng băng, chỗ Ô Sửu cùng hai nữ tử xuất hiện. Khung cảnh này gắn với sự lộ diện của Huyền Âm ma khí.","detail":"Khi Huyền Âm ma khí cuốn quanh khu vực Anh Lý Thú, một nam hai nữ xuất hiện ở phía bên kia yêu thú. Đây là điểm bùng phát xung đột giữa Ô Sửu, Cực Âm Đảo và Lục Liên Điện.","theLucLienQuan":["Cực Âm Đảo","Lục Liên Điện"],"nguon":["@c0382"]},{"id":"pham-vi-bich-thuy-thanh-giap-dai-tran","name":"Phạm vi Bích Thủy Thanh Giáp Đại Trận","cn":"","capDo":"khac","parentId":"hoang-dao-vo-danh","blurb":"Phạm vi Bích Thủy Thanh Giáp Đại Trận là không gian trận pháp quanh đảo vô danh nơi Cổ trưởng lão bị dẫn vào. Bên trong, cảnh tượng biến thành đại hải bát ngát và áp lực trận pháp đè ép người trong trận.","detail":"Sau khi Cổ trưởng lão truy theo Hàn Lập xuống đảo vô danh, hắn tiến vào phạm vi Bích Thủy Thanh Giáp Đại Trận. Trận pháp khiến bốn phía hóa thành đại hải bát ngát, tạo áp lực lên thân thể hắn, rồi được Hàn Lập dùng chủ trận kỳ tăng thêm uy lực.","theLucLienQuan":[],"nguon":["@c0383"]},{"id":"vung-bien-phuc-kich-co-truong-lao","name":"Vùng biển phục kích Cổ trưởng lão","cn":"","capDo":"khac","parentId":"dai-hai","blurb":"Vùng biển nơi Hàn Lập bố trí đại trận và phối hợp Khúc Hồn vây giết Cổ trưởng lão.","detail":"Tại khu vực này, nước biển, băng thương, huyết quang, phi châm, độn thuật và áp lực trận pháp cùng được Hàn Lập sử dụng để phá phòng hộ của Cổ trưởng lão rồi chém đầu đối thủ.","theLucLienQuan":["Lục Liên Điện"],"nguon":["@c0384"]},{"id":"day-bien-noi-han-lap-an-nap","name":"Đáy biển nơi Hàn Lập ẩn nấp","cn":"","capDo":"khac","parentId":"dai-hai","blurb":"Đáy biển nơi Hàn Lập và Khúc Hồn lặn xuống để tránh thần thức cường đại sau trận giết Cổ trưởng lão.","detail":"Sau khi rời chiến trường hơn hai ba mươi hải lý, Hàn Lập lặn xuống sâu hơn mười trượng, dùng tấm lụa mỏng và vô danh khẩu quyết che giấu khí tức. Hắn ẩn tại đây hơn nửa tháng trước khi rời đi.","theLucLienQuan":[],"nguon":["@c0384"]},{"id":"ba-dai-dao","name":"Ba đại đảo","cn":"","capDo":"khac","parentId":"loan-tinh-hai","blurb":"Ba đại đảo cùng Khôi Tinh Đảo là trung tâm của hải đồ trong ngọc giản Hàn Lập sử dụng.","detail":"Hàn Lập dựa vào ngọc giản hải đồ lấy Khôi Tinh Đảo và ba đại đảo làm trung tâm để phán đoán vị trí và tra các đảo nhỏ lân cận.","theLucLienQuan":[],"nguon":["@c0385"]},{"id":"hai-vien-dao","name":"Hải Viên Đảo","cn":"","capDo":"gioi-nho","parentId":"loan-tinh-hai","blurb":"Hòn đảo trung bình có nhiều phàm nhân và tu sĩ cấp thấp, được Hàn Lập chọn làm nơi ẩn thân kết đan.","detail":"Hải Viên Đảo nhỏ hơn Khôi Tinh Đảo nhưng lớn hơn các tiểu đảo xung quanh, không có đảo chủ, ra vào tương đối tự do. Đảo có linh mạch rộng nhưng linh khí không cao, không có linh nhãn hấp dẫn cao giai tu sĩ, nên trở thành nơi tụ tập của tán tu cấp thấp và thích hợp để Hàn Lập ẩn thân lâu dài.","theLucLienQuan":["Tán tu Hải Viên Đảo","Tiểu thương gia thu mua Hải Viên"],"nguon":["@c0385"]},{"id":"ngon-nui-hoang-tren-hai-vien-dao","name":"Ngọn núi hoang trên Hải Viên Đảo","cn":"","capDo":"khac","parentId":"hai-vien-dao","blurb":"Vị trí động phủ tạm nơi Hàn Lập và Khúc Hồn bế quan bốn năm. Dị tượng kết Sát Đan của Khúc Hồn bùng phát tại đây, kéo nhiều tán tu cấp thấp tới gần.","detail":"Trên ngọn núi hoang này, mây đen, lôi điện và lốc xoáy linh khí xuất hiện sau bốn năm bế quan, hút linh khí hơn mười dặm quanh vùng. Sau khi các tán tu bị cảnh cáo rút lui, khu vực quanh núi về sau có thêm nhiều động phủ mới vì họ hy vọng gặp vị tiền bối Kết Đan.","theLucLienQuan":["Tán tu Hải Viên Đảo"],"nguon":["@c0386"]},{"id":"dong-phu-that-cua-han-lap-tren-tieu-hoan-dao","name":"Động phủ thật của Hàn Lập trên Tiểu Hoàn Đảo","cn":"","capDo":"khac","parentId":"tieu-hoan-dao","blurb":"Động phủ thật Hàn Lập quay về sau khi rời Hải Viên Đảo. Bên ngoài động phủ thật giả và ba tòa trận pháp đều nguyên vẹn bất thường, còn mật thất nuôi kỳ trùng khiến hắn kinh hãi.","detail":"Hơn một tháng sau khi Khúc Hồn kết Sát Đan, Hàn Lập trở lại Tiểu Hoàn Đảo để lấy kỳ trùng và chuẩn bị rời Tây Nam Hải Vực. Hắn dò xét không thấy tu sĩ mai phục, nhưng động phủ thật giả cùng ba trận pháp vẫn nguyên vẹn ngoài dự liệu, khiến hắn cảnh giác trước khi vào mật thất nuôi kỳ trùng.","theLucLienQuan":["Hàn Lập"],"nguon":["@c0386"]},{"id":"mat-that-nuoi-duong-ky-trung","name":"Mật thất nuôi dưỡng kỳ trùng","cn":"","capDo":"khac","parentId":"dong-phu-that-cua-han-lap-tren-tieu-hoan-dao","blurb":"Khu mật thất trong động phủ của Hàn Lập dùng để nuôi kỳ trùng, bị Phệ Kim Trùng phá hủy trong chương này.","detail":"Hàn Lập kiểm tra khu mật thất nuôi kỳ trùng và phát hiện cấm chế vốn dùng để ngăn trùng đào thoát đã biến mất, cửa đá chi chít lỗ nhỏ, các mật thất đều trống rỗng. Ngay cả những kỳ trùng cũ thuộc bách bảng cũng mất tích, chỉ còn lại manh mối là vỏ trùng bạc.","theLucLienQuan":[],"nguon":["@c0387"]},{"id":"duoc-vien-trong-dong-phu-han-lap","name":"Dược viên trong động phủ Hàn Lập","cn":"","capDo":"khac","parentId":"dong-phu-that-cua-han-lap-tren-tieu-hoan-dao","blurb":"Khu dược viên nơi Hàn Lập phát hiện ngân cầu Phệ Kim Trùng treo dưới tán cây.","detail":"Sau khi tìm thấy trùng xác bạc, Hàn Lập mở rộng thần thức và phát hiện trong dược viên có một ngân cầu yêu dị dưới tán cây um tùm. Đây là nơi Phệ Kim Trùng quần tụ trước khi bị Hàn Lập thử uy lực và bắt sống.","theLucLienQuan":[],"nguon":["@c0387"]},{"id":"tieu-dao-ngoai-khoi-tinh-dao","name":"Tiểu đảo","cn":"","capDo":"khac","parentId":"loan-tinh-hai","blurb":"Tiểu đảo nơi Hàn Lập và Khúc Hồn vừa rời khỏi thì gặp nhóm chấp pháp Khôi Tinh Đảo mai phục.","detail":"Hàn Lập cùng Khúc Hồn rời khỏi tiểu đảo bằng Thần Phong Chu, lập tức phát hiện bảy tám tu sĩ Trúc Cơ kỳ ẩn nấp gần đó và bị vây bắt.","theLucLienQuan":["Khôi Tinh Đảo"],"nguon":["@c0388"]},{"id":"tay-nam-hai-vuc","name":"Tây Nam Hải Vực","cn":"","capDo":"vuc","parentId":"loan-tinh-hai","blurb":"Khu vực Hàn Lập đang rời khỏi sau khi bị truy nã. Hắn nhận định nơi này không thể ở lâu và cần tìm hải đồ rộng hơn trước khi đi xa.","detail":"Tây Nam Hải Vực là hải vực nơi Hàn Lập từng hoạt động trước chương này. Do đã bị truy nã, hắn quyết định rời khỏi khu vực, nhưng vì bản đồ trong tay chỉ giới hạn ở nơi đây nên phải ghé phường thị vùng biên để mua thêm tin tức, hải đồ và điển tịch.","theLucLienQuan":[],"nguon":["@c0389"]},{"id":"tieu-dao-phuong-thi-vung-bien","name":"Tiểu đảo phường thị vùng biên","cn":"","capDo":"khac","parentId":"tay-nam-hai-vuc","blurb":"Hòn đảo nhỏ ở ranh giới Tây Nam Hải Vực và hải vực khác, có phường thị khá phát đạt. Hàn Lập dừng lại nửa ngày để mua nguyên liệu, điển tịch và hải đồ.","detail":"Sau một tháng rời Tây Nam Hải Vực, Hàn Lập dừng tại một tiểu đảo phường thị vùng biên. Tại đây, hắn cùng Khúc Hồn che giấu dung mạo rồi mua sắm nhiều nguyên liệu, ngọc giản điển tịch và hải vực đồ trước khi rời đảo ngay trong ngày.","theLucLienQuan":[],"nguon":["@c0389"]},{"id":"noi-tinh-hai","name":"Nội Tinh Hải","cn":"","capDo":"vuc","parentId":"loan-tinh-hai","blurb":"Phần hải vực đã được thăm dò trong Loạn Tinh Hải. Người trong truyện ngày nay thường gọi khu vực này là Loạn Tinh Hải theo nghĩa hẹp.","detail":"Nội Tinh Hải là tên gọi các hải vực đã được tu sĩ thăm dò và khai phá trong Loạn Tinh Hải. Nó đối lập với Ngoại Tinh Hải, vùng bên ngoài chưa được kiểm tra hết và còn nhiều yêu thú cường đại.","theLucLienQuan":["Tinh Cung"],"nguon":["@c0389"]},{"id":"ngoai-tinh-hai","name":"Ngoại Tinh Hải","cn":"外星海","aliases":["Yêu Hải"],"capDo":"vuc","parentId":"loan-tinh-hai","blurb":"Vùng ngoài các hải vực đã được thăm dò, còn gọi là Yêu Hải. Nơi này có nhiều yêu thú mạnh, là mục tiêu của tu sĩ đi săn qua truyền tống trận từ Thiên Tinh Thành.","detail":"Ngoại Tinh Hải nằm bên ngoài Nội Tinh Hải, nơi có nhiều yêu thú cường đại, thậm chí được nghe nói có thể chống lại tu sĩ Nguyên Anh kỳ. Thiên Tinh Thành có truyền tống trận đưa tu sĩ tới các Yêu Thú Đảo trong vùng này để săn yêu thú lấy Yêu Đan.","theLucLienQuan":["Tinh Cung"],"nguon":["@c0389","@c0497","@c0514"]},{"id":"thien-tinh-thanh","name":"Thiên Tinh Thành","cn":"天星城","capDo":"thanh","parentId":"noi-tinh-hai","blurb":"Thành thị siêu cấp do Thiên Tinh Cung xây trên một đảo lớn trong Nội Tinh Hải. Đây là trung tâm Tinh Cung, nơi giao thương tự do, tổ chức Trích Tinh đại hội và có truyền tống trận tới Ngoại Tinh Hải.","detail":"Thiên Tinh Thành là trung tâm của Tinh Cung, do Thiên Tinh Cung biến một đảo lớn trong Nội Tinh Hải thành thành thị siêu cấp. Trong thành cấm tranh đấu, tu sĩ ra vào khá tự do nhưng ở lâu phải nộp linh thạch; nơi này phồn hoa, có thương gia, đấu giá, Trích Tinh đại hội và truyền tống trận tới Yêu Thú Đảo ở Ngoại Tinh Hải.","theLucLienQuan":["Tinh Cung"],"nguon":["@c0389","@c0400","@c0497"]},{"id":"ngoai-thap-nhi-tu-tinh","name":"Ngoại Thập Nhị Tứ Tinh","cn":"","capDo":"khac","parentId":"loan-tinh-hai","blurb":"Nhóm tinh đảo bên ngoài thuộc hệ thống Tinh Cung. Đảo chủ ngoại tinh đảo trăm năm một lần được chọn qua khiêu chiến công khai tại Thiên Tinh Thành.","detail":"Ngoại Thập Nhị Tứ Tinh là nhóm tinh đảo bên ngoài trong cơ chế tinh đảo của Tinh Cung. Chức đảo chủ ở các ngoại tinh đảo được chọn qua Trích Tinh đại hội trăm năm một lần, nơi tu sĩ công khai khiêu chiến tại Thiên Tinh Thành.","theLucLienQuan":["Tinh Cung"],"nguon":["@c0389"]},{"id":"noi-thap-nhi-tinh-dao","name":"Nội Thập Nhị Tinh Đảo","cn":"","capDo":"khac","parentId":"noi-tinh-hai","blurb":"Nhóm tinh đảo trung bộ trong hệ thống Tinh Cung. Người đứng đầu được lựa chọn theo cơ chế nội bộ do hai vị đảo chủ đại nhân tổ chức.","detail":"Nội Thập Nhị Tinh Đảo là nhóm tinh đảo ở vùng trung bộ trong hệ thống quản lý của Tinh Cung. Điển tịch cho biết chức đứng đầu nội tinh đảo do hai vị đảo chủ đại nhân lựa chọn và bổ nhiệm.","theLucLienQuan":["Tinh Cung"],"nguon":["@c0389"]},{"id":"yeu-thu-dao","name":"Yêu Thú Đảo","cn":"","capDo":"khac","parentId":"ngoai-tinh-hai","blurb":"Hơn mười cô đảo lớn nhỏ ở Ngoại Tinh Hải có linh khí, được chọn làm điểm đến truyền tống. Tu sĩ tới đây săn yêu thú để lấy Yêu Đan.","detail":"Yêu Thú Đảo là các cô đảo lớn nhỏ nằm trong Ngoại Tinh Hải, được tiền nhân chọn làm điểm đến của truyền tống trận trong Thiên Tinh Thành. Chúng là nơi tu sĩ tới săn yêu thú, lấy Yêu Đan để đổi linh thạch hoặc dùng làm tài nguyên tu luyện.","theLucLienQuan":["Tinh Cung"],"nguon":["@c0389"]},{"id":"thien-tinh-thanh-map","name":"Thiên Tinh Thành","cn":"天星城","capDo":"thanh","parentId":"loan-tinh-hai","blurb":"Đệ nhất đại thành của Loạn Tinh Hải, siêu cấp thành thị chiếm trọn một hải đảo.","detail":"Lấy cự sơn cao tới mây làm trung tâm, kiến trúc xoắn ốc phủ từ chân núi tới bờ đảo. Thành có tường đá ven biển cao hơn mười trượng, cửa thành nhỏ, khu phàm nhân với nhà đá và cửa hàng. Cho phép tu sĩ ngự khí phi hành trong thành, không có cấm chế phi hành rõ ràng.","theLucLienQuan":["Thiên Tinh Thành"],"nguon":["@c0390"]},{"id":"cua-thanh-nho-thien-tinh-thanh","name":"Cửa thành nhỏ của Thiên Tinh Thành","cn":"","capDo":"khac","parentId":"thien-tinh-thanh-map","blurb":"Cửa thành nơi tu sĩ và phàm nhân làm thủ tục vào Thiên Tinh Thành.","detail":"Nằm dưới bức tường đá cao hơn mười trượng. Tu sĩ nộp linh thạch và nhận thân phận hoàn tại đây. Phía sau là ngã tư có nhà đá và cửa hàng phàm nhân.","theLucLienQuan":["Thiên Tinh Thành"],"nguon":["@c0390"]},{"id":"thanh-son","name":"Thánh sơn","cn":"圣山","capDo":"khac","parentId":"thien-tinh-thanh","blurb":"Linh mạch trời sinh trong Thiên Tinh thành, chia tám mươi mốt tầng. Năm mươi tầng dưới cho ngoại lai tu sĩ thuê trụ trạch/động phủ, ba mươi tầng trên dành cho người Tinh Cung, tầng cao nhất là Thánh cung nơi ở của hai vị thánh chủ.","detail":"Mỗi vòng từ dưới lên là một tầng, tổng cộng tám mươi mốt tầng. Năm mươi tầng dưới cho ngoại lai tu sĩ thuê bằng linh thạch với phí tính theo chu kỳ trăm năm, tầng càng cao phí càng đắt nhưng linh khí càng tốt. Ba mươi tầng trên dành riêng cho đại nhân Tinh Cung. Tầng cao nhất là Thánh cung, nơi ở của hai vị thánh chủ đại nhân, cấm bất kỳ ai tùy tiện tiến vào.","theLucLienQuan":["Tinh Cung"],"nguon":["@c0391"]},{"id":"dong-phu-tang-39-han-lap","name":"Động phủ tầng ba mươi chín của Hàn Lập","cn":"","capDo":"khac","parentId":"thanh-son","blurb":"Động phủ Hàn Lập thuê ở tầng ba mươi chín Thánh sơn với giá hai ngàn bảy trăm linh thạch cho trăm năm. Yên tĩnh, linh khí tốt không kém động phủ cũ ở Thiên Nam, có dược viên, mật thất nuôi trùng và ba bộ đại trận phòng hộ do Hàn Lập tự bố trí.","detail":"Hàn Lập chọn động phủ này sau khi xem nhiều ngọc giản giới thiệu. Động phủ sẵn có cấm chế lợi hại nhưng Hàn Lập không hoàn toàn tin tưởng nên tự bố trí thêm ba bộ đại trận. Bên trong có dược viên để trồng dược thảo dự trữ linh dược, và mật thất vài chục trượng được hắn lát mỹ ngọc thượng phẩm rồi đưa Phệ Kim Trùng vào nuôi dưỡng.","theLucLienQuan":["Tinh Cung"],"nguon":["@c0391"]},{"id":"chan-nui-thanh-son","name":"Chân núi Thánh sơn","cn":"","capDo":"khac","parentId":"thanh-son","blurb":"Khu vực dưới chân Thánh sơn có lầu các chuyên xử lý việc thuê trụ trạch và động phủ, nơi Hàn Lập cùng Khúc Hồn và Lỗ Nhị đến giao dịch thuê động phủ.","detail":"Hàn Lập dùng Thần Phong Chu bay đến đây, để Khúc Hồn ra mặt giao dịch với bạch y tu sĩ Tinh Cung. Lầu các này là nơi xử lý thủ tục thuê nơi tu luyện trên Thánh sơn.","theLucLienQuan":["Tinh Cung"],"nguon":["@c0391"]},{"id":"phuong-thi-thien-tinh-thanh","name":"Phường thị Thiên Tinh thành","cn":"","capDo":"khac","parentId":"thien-tinh-thanh","blurb":"Khu phường thị trong Thiên Tinh thành, nơi Hàn Lập yêu cầu Lỗ Nhị dẫn đi xem và giới thiệu các cửa hiệu quan trọng, sau đó mua mỹ ngọc thượng phẩm tại đây.","detail":"Sau khi thuê xong động phủ, Hàn Lập dành nửa ngày cùng Lỗ Nhị khảo sát phường thị, tìm hiểu các cửa hiệu và mua sắm vật liệu cần thiết cho tu luyện.","theLucLienQuan":[],"nguon":["@c0391"]},{"id":"duoc-vien-dong-phu-tang-39","name":"Dược viên trong động phủ tầng ba mươi chín","cn":"","capDo":"khac","parentId":"dong-phu-tang-39-han-lap","blurb":"Khu vườn không nhỏ trong động phủ tầng ba mươi chín, được Hàn Lập dùng để trồng nhiều loại dược thảo dự trữ linh dược.","detail":"Dược viên có sẵn trong động phủ khi thuê. Hàn Lập đem dược thảo trồng vào đây để chuẩn bị nguồn linh dược sử dụng lâu dài.","theLucLienQuan":[],"nguon":["@c0391"]},{"id":"mat-that-ngoc-bich-dong-phu-tang-39","name":"Mật thất ngọc bích trong động phủ tầng ba mươi chín","cn":"","capDo":"khac","parentId":"dong-phu-tang-39-han-lap","blurb":"Gian mật thất rộng vài chục trượng được Hàn Lập lát kín bằng mỹ ngọc thượng phẩm để nuôi dưỡng Phệ Kim Trùng.","detail":"Hàn Lập mua mỹ ngọc thượng phẩm ở phường thị rồi đem vây kín mật thất, đưa Phệ Kim Trùng vào bên trong và kỳ vọng bồi dưỡng chúng thành trợ lực.","theLucLienQuan":[],"nguon":["@c0391"]},{"id":"thanh-cung","name":"Thánh cung","cn":"圣宫","capDo":"khac","parentId":"thanh-son","blurb":"Tầng cao nhất của Thánh sơn, nơi ở của hai vị thánh chủ đại nhân, cấm bất kỳ ai tùy tiện tiến vào.","detail":"Được Lỗ Nhị nhắc tới khi giới thiệu phân tầng Thánh sơn. Tầng tối thượng này thuộc về hai vị thánh chủ Tinh Cung.","theLucLienQuan":["Tinh Cung"],"nguon":["@c0391"]},{"id":"tinh-khong-dien-map","name":"Tinh Không Điện","capDo":"khac","parentId":"thien-tinh-thanh","blurb":"Đại điện đá Đại Lý màu trắng ở tầng năm mươi Thiên Tinh Thành, chứa nhiều truyền tống trận dẫn tới các yêu thú đảo Ngoại Tinh Hải.","detail":"Điểm khởi hành truyền tống chính của Thiên Tinh Thành, do bạch y tu sĩ Tinh Cung Kết Đan quản trận. Mặt trước có biển lớn ghi ba chữ kim phấn, bên trong đại sảnh rộng với nhiều truyền tống trận ghi rõ địa điểm.","theLucLienQuan":["Tinh Cung"],"nguon":["@c0393"]},{"id":"ngung-thuy-dao","name":"Ngưng Thúy Đảo","capDo":"khac","parentId":"ngoai-tinh-hai","blurb":"Yêu thú đảo trong Ngoại Tinh Hải, điểm đến đầu tiên của Hàn Lập và Khúc Hồn khi ra biển săn yêu thú.","detail":"Đảo có thạch ốc truyền tống do tu sĩ Tinh Cung Trúc Cơ trung kỳ trấn giữ, xung quanh là khu phố nhỏ tạm bợ với cửa hiệu tạp hóa, pháp khí, phù lục và nơi thu mua hàng hóa, kiến trúc sơ sài bằng đá thô hoặc gỗ, bố trí lộn xộn. Ngoài yêu thú cấp cao còn có nguy hiểm từ bại hoại và tà tu đánh lén.","theLucLienQuan":["Tinh Cung"],"nguon":["@c0393"]},{"id":"thach-oc-truyen-tong-ngung-thuy-dao","name":"Thạch ốc truyền tống trên Ngưng Thúy Đảo","capDo":"khac","parentId":"ngung-thuy-dao","blurb":"Căn phòng đơn sơ chứa truyền tống trận trên Ngưng Thúy Đảo, có tu sĩ Tinh Cung trấn giữ và được trận pháp cấm chế bao phủ.","detail":"Bên trong có tu sĩ Tinh Cung Trúc Cơ trung kỳ khoanh chân đả tọa. Hàn Lập cảm nhận linh khí dao động khác thường, suy rằng nơi này được trận pháp cấm chế bảo vệ.","theLucLienQuan":["Tinh Cung"],"nguon":["@c0393"]},{"id":"khu-pho-nho-ngung-thuy-dao","name":"Khu phố nhỏ quanh thạch ốc Ngưng Thúy Đảo","capDo":"khac","parentId":"ngung-thuy-dao","blurb":"Cụm cửa hiệu tạm bợ phục vụ tu sĩ săn yêu, gồm cửa hàng tạp hóa, pháp khí, phù lục và nơi thu mua hàng hóa, dựng bằng đá thô hoặc gỗ xung quanh thạch ốc truyền tống.","detail":"Kiến trúc sơ sài, đông một tòa nhà tây một gian hang, bố trí lộn xộn lấy thạch ốc truyền tống làm trung tâm, khiến Hàn Lập ngạc nhiên.","theLucLienQuan":[],"nguon":["@c0393"]},{"id":"hong-ho-dao","name":"Hồng Hô đảo","cn":"","aliases":["Tiểu đảo san hô đỏ","Đảo san hô màu hồng"],"capDo":"khac","parentId":"ngoai-tinh-hai","blurb":"Tiểu đảo toàn màu hỏa hồng, cấu tạo từ san hô đỏ tươi chất đống, dưới ánh nắng sáng lấp lóe. Nằm cách Ngưng Thúy Đảo ba ngày bay.","detail":"Đảo nằm trong Ngoại tinh hải, cách Ngưng Thúy Đảo ba ngày bay bằng Thần Phong Chu tốc độ cực nhanh. Toàn đảo phủ san hô đỏ tươi sáng. Là đích đến mà Hàn Lập chủ đích tìm kiếm theo kế hoạch riêng.","theLucLienQuan":[],"nguon":["@c0394"]},{"id":"thanh-ha-tra-quan","name":"Thanh Hà trà quán","cn":"","capDo":"khac","parentId":null,"blurb":"Quán trà gần nơi Hàn Lập giao dịch, có lầu hai với phòng tao nhã riêng. Diệu Âm Môn đã sắp xếp sẵn phòng tại đây để gặp Hàn Lập.","detail":"Phạm Tĩnh Mai mời Hàn Lập đến Thanh Hà trà quán. Trung niên nhân Diệu Âm Môn đã sắp xếp phòng tao nhã trên lầu hai, bên trong có lão giả áo xám ngồi sẵn pha trà.","theLucLienQuan":["Diệu Âm Môn"],"nguon":["@c0399"]},{"id":"dao-vo-danh-tap-ket","name":"Đảo vô danh (điểm tập kết)","capDo":"khac","parentId":null,"blurb":"Đảo nhỏ vô danh với đỉnh núi phạm vi mười trượng, nơi Diệu Âm môn triệu tập nhân mã chuẩn bị xuất phát đoạt lại hàng hóa.","detail":"Đỉnh núi trên một đảo vô danh, phạm vi khoảng mười trượng, nơi Phạm phu nhân và Trác Như Đình tập kết khoảng mười mấy tu sĩ gồm năm Kết đan kỳ và hơn mười Trúc cơ hậu kỳ trước khi xuất phát.","theLucLienQuan":["Diệu Âm Môn"],"nguon":["@c0402"]},{"id":"nguyen-quy-dao","name":"Nguyên Quy Đảo","cn":"","capDo":"khac","parentId":"loan-tinh-hai","blurb":"Hải đảo trên Loạn Tinh Hải bị Xích Hỏa lão quái độc chiếm.","detail":"Đảo do tu sĩ ma đạo Kết Đan hậu kỳ Xích Hỏa lão quái một mình thống trị, không ai dám xâm phạm.","theLucLienQuan":["Nguyên Quy Đảo"],"nguon":["@c0403"]},{"id":"hu-thien-dien","name":"Hư Thiên Điện","cn":"虚天殿","capDo":"khac","parentId":null,"blurb":"Bí cảnh xuất hiện mỗi ba trăm năm, sắp đến hạn. Hư Thiên tàn đồ là bản đồ/chìa khóa liên quan.","detail":"Hư Thiên Điện là nơi bí cảnh xuất hiện theo chu kỳ ba trăm năm. Thời gian xuất hiện tiếp theo sắp đến. Hư Thiên tàn đồ bị chia nhiều phần, là bản đồ hoặc chìa khóa để tiến vào. Cực Âm lão tổ và người trung niên Ẩn Sát Môn đều nhắm tới.","theLucLienQuan":["Cực Âm đảo","Ẩn Sát Môn"],"nguon":["@c0405","@c0429","@c0431"],"tabs":{"tienTrinh":[{"chuong":"@c0431","loai":"xuất hiện","importance":"major","giaiDoan":"Hàn Lập phát hiện và tiến vào","text":"Hàn Lập theo bản đồ tìm tới vùng biển, phát hiện tòa cung điện bạch ngọc lơ lửng trên không trung. Ẩn nấp bảy tám ngày quan sát tu sĩ Kết Đan liên tục bay vào, sau đó dùng địa đồ rót linh lực xuyên qua màn hào quang kim sắc tiến vào. Khám phá thông đạo có cấm chế chặn thần thức và đại sảnh với mười ngọc trụ khổng lồ.","anchor":"Vừa nhìn thấy tòa thành bằng ngọc trôi nổi trên không trung, Hàn Lập hít vào một hơi, vẻ mặt kinh ngạc"}]}},{"id":"thong-thien-vu-hai","name":"Thông Thiên Vụ Hải","cn":"","capDo":"vuc","parentId":null,"blurb":"Nơi người trung niên Ẩn Sát Môn ẩn náu hơn mười năm để trốn Cực Âm lão tổ.","detail":"Vùng biển sương mù nơi thủ lĩnh Ẩn Sát Môn (cựu đệ tử Cực Âm lão tổ) ẩn náu hơn mười năm. Lần này ra ngoài một phần vì Hư Thiên Điện sắp xuất hiện.","theLucLienQuan":["Ẩn Sát Môn"],"nguon":["@c0405"]},{"id":"nguyen-tu-son-phong","name":"Nguyên Từ sơn phong","cn":"","capDo":"khac","parentId":"thien-tinh-thanh","blurb":"Ngọn núi tại Thiên Tinh thành, nguồn sức mạnh khiến Thiên Tinh song thánh gần như vô địch khi ở đây.","detail":"Nguyên Từ sơn phong nằm tại Thiên Tinh thành, là nguồn gốc uy lực khiến Thiên Tinh song thánh dựa vào đó cơ hồ vô địch. Chỉ khi ở gần Nguyên Từ sơn phong, hiệu quả tu luyện Nguyên Từ thần quang mới phát huy tối đa.","theLucLienQuan":["Thiên Tinh cung"],"nguon":["@c0408"]},{"id":"hon-dao-nho-vo-danh-c0408","name":"Hòn đảo nhỏ vô danh (ẩn thân)","cn":"","capDo":"khac","parentId":"loan-tinh-hai","blurb":"Hòn đảo nhỏ vô danh nơi Hàn Lập và Khúc Hồn ẩn thân dưới đất sau khi đào thoát khỏi yêu thi.","detail":"Sau khi vây khốn yêu thi tạm thời, Hàn Lập và Khúc Hồn phi độn hơn trăm dặm, rẽ trái ngoặt phải nhiều lần, tìm được hòn đảo nhỏ vô danh, chui sâu vào đất hơn mười trượng để ẩn thân.","theLucLienQuan":[],"nguon":["@c0408"]},{"id":"long-hung-khach-san","name":"Long Hưng Khách Sạn","capDo":"khac","parentId":"thien-tinh-thanh","blurb":"Khách sạn sang trọng tại Thiên Tinh Thành, tầng 1-2 dành phàm nhân, tầng 3 đặc biệt dành tu sĩ tạm trú.","detail":"Địa điểm Hàn Lập gặp Tử Linh tiên tử (Uông Ngưng). Phòng tầng ba có cấm chế cảnh giới, cần thần thức xác nhận mới mở cửa.","theLucLienQuan":[],"nguon":["@c0409"]},{"id":"thanh-truc-tieu-hien","name":"Thanh Trúc Tiểu Hiên","cn":"青竹小轩","capDo":"khac","parentId":"phuong-thi","blurb":"Cửa hàng nhỏ Hàn Lập mua lại (trước là Lý Thị Tạp Hóa) ở phường thị Thiên Tinh Thành, bán phù lục, dược tài và pháp khí cấp thấp.","detail":"Tiệm nhỏ tại phường thị Thiên Tinh Thành, nguyên là Lý Thị Tạp Hóa, được Hàn Lập mua lại đổi tên thành Thanh Trúc Tiểu Hiên. Hàn Lập dịch dung giả phàm nhân ngồi đây suốt ngày nghiên cứu luyện khí và trận pháp, ma luyện nhập thế tâm cảnh theo yêu cầu Đại Diễn Quyết tầng 4. Khúc Hồn phụ trách tiếp khách. Bày bán phù lục, dược tài, và pháp khí cấp thấp do Hàn Lập tự luyện.","theLucLienQuan":[],"nguon":["@c0412"]},{"id":"co-tu-si-di-chi","name":"Cổ tu sĩ di chỉ","capDo":"khac","parentId":"loan-tinh-hai","blurb":"Địa điểm được ghi trên bản đồ trong trân châu, nghi là di chỉ của cổ tu sĩ. Bị đại trận bao phủ, Kim Thanh và bằng hữu không thể tiến vào.","detail":"Kim Thanh cùng bằng hữu tốn năm sáu năm tìm ra địa điểm này dựa theo bản đồ trong hai viên trân châu. Nơi đây bị đại trận cấm chế bao phủ, hai người không có kiến thức trận pháp nên thất vọng quay về, sau đó mời Hàn Lập trợ giúp.","theLucLienQuan":[],"nguon":["@c0415"]},{"id":"dao-hoang-tho-son","name":"Đảo hoang (Thổ Sơn)","cn":"土山","capDo":"khac","parentId":"loan-tinh-hai","blurb":"Hòn đảo lớn phương viên trên ngàn dặm trên Loạn Tinh Hải, toàn đất vàng không cây cối không linh mạch. Có bão cát bao quanh khu vực núi đất cao ngàn trượng, sườn núi bị đại trận phong ấn cổ tu sĩ bao phủ, bên trong nghi là di chỉ.","detail":"Đảo hoang nằm cách Thiên Tinh Thành nửa ngày phi hành. Toàn bộ đảo đều là đất, khắp nơi bụi vàng. Kim Thanh dùng bản đồ cổ tìm ra đảo, hỏi phàm nhân quanh đó xác nhận là đảo hoang. Khi bay tới gần, bão cát dữ dội xuất hiện; vượt qua hơn mười dặm bão cát thì thấy tòa núi đất cao ngàn trượng màu vàng. Tại chân núi, nhóm Hồ Nguyệt đã dựng thạch ốc bằng Thạch Hóa thuật để đợi.","theLucLienQuan":[],"nguon":["@c0416"]},{"id":"suon-nui-dai-tran-co-dai","name":"Sườn núi có đại trận cổ đại","cn":"","capDo":"khac","parentId":null,"blurb":"Khu vực dốc thoai thoải trên sườn núi, nơi đại trận cổ đại song thuộc tính Thổ–Phong tồn tại, bao phủ bởi hoàng vụ dày đặc.","detail":"Sườn núi nơi nhóm Hàn Lập đến phá trận. Ban đầu bao phủ bởi hoàng vụ nồng đậm — tầng huyễn trận che mắt. Sau khi Hàn Lập phá tầng ngoài, sương mù biến mất lộ ra tầng hào quang vàng nhạt bao phủ phạm vi hơn trăm trượng — đại trận thực sự bên trong.","theLucLienQuan":[],"nguon":["@c0417"]},{"id":"tam-duong-chi-dia","name":"Tam dương chi địa","cn":"三阳之地","capDo":"khac","parentId":"co-tu-si-di-chi","blurb":"Khu vực cực đoan do đạo cấm chế cuối cùng của đại trận cổ tạo ra, môi trường khiến yêu linh Sí Ác vĩnh sinh bất diệt.","detail":"Tam dương chi địa là khu vực bên trong đạo cấm chế cuối cùng bảo vệ cột đá cổ văn tại cổ tu sĩ di chỉ. Nơi đây là môi trường cực kỳ đặc thù, chỉ có thể hình thành trong điều kiện đặc biệt, khiến yêu linh hỏa hệ Sí Ác có thể vĩnh sinh bất diệt. Thạch Điệp giải thích rằng nếu không hiểu rõ mà cưỡng phá sẽ bị Sí Ác tấn công.","theLucLienQuan":[],"nguon":["@c0418"]},{"id":"hoang-dao-quai-nhan","name":"Hoang đảo (đảo của quái nhân)","cn":"","capDo":"khac","parentId":"loan-tinh-hai","blurb":"Hoang đảo nơi quái nhân đảo chủ tự xưng ở hơn mấy trăm năm, nhóm Hàn Lập đến phá cấm chế. Hồ Nguyệt và Kim Thanh lần trước đến mà không gặp ai.","detail":"Hoang đảo giữa biển, quái nhân tự phong đảo chủ ẩn cư hơn mấy trăm năm trông nom cấm chế. Trước đó Hồ Nguyệt và Kim Thanh từng đến khảo sát mà không phát hiện người ở. Nhóm Hàn Lập đang bố trí trận pháp phá cấm chế tại đây thì bị quái nhân xuất hiện chặn đường.","theLucLienQuan":[],"nguon":["@c0419"]},{"id":"dai-sanh-ngam-phong-linh-tru","name":"Đại sảnh ngầm dưới Phong Linh Trụ","cn":"","capDo":"khac","parentId":"co-tu-si-di-chi","blurb":"Đại sảnh rộng hơn 20 trượng nằm sâu dưới lòng đất bên dưới Phong Linh Trụ, trần khảm Dạ minh châu, vách tường lấp lánh. Giữa sảnh có ao thạch nhũ ngàn năm với đóa Thất Hà Liên và bộ hài cốt bí ẩn.","detail":"Nằm sâu dưới lòng đất, đi xuống theo bậc thang đá trắng khoảng một khắc từ vị trí Phong Linh Trụ. Diện tích hơn 20 trượng, trần khảm nhiều viên Dạ minh châu to bằng nắm tay chiếu sáng, vách tường lấp lánh do pháp thuật. Hai bên sảnh có hai cửa hình bán nguyệt thông đi nơi khác, chưa khám phá. Chính giữa sảnh có ao nhỏ chứa dung dịch trắng sữa (thạch nhũ ngàn năm) với đóa Thất Hà Liên ba màu mọc trong đó. Bên cạnh ao là bộ hài cốt trắng tinh như ngọc, đầu lâu bị mũi tên xanh biếc cắm xuyên ghim chặt xuống đất.","theLucLienQuan":[],"nguon":["@c0422"]},{"id":"ao-ngoc-nuoc-doc","name":"Ao ngọc (nước trắng sữa)","cn":"","capDo":"khac","parentId":"co-tu-si-di-chi","blurb":"Ao do mỹ ngọc lấp lánh tạo thành, chứa nước màu trắng sữa cực kỳ kịch độc — ăn mòn da thịt ngay lập tức, có thể phân hủy toàn bộ cơ thể tu sĩ trong thời gian ngắn.","detail":"Thất Hà Liên mọc trên mặt ao này. Vốn là thạch nhũ ngàn năm không có độc, nhưng theo phán đoán của Hàn Lập, có người hạ độc. Bên ao có bộ hài cốt trắng — tay phải đen một mảng, ngón trỏ bị thiếu một đoạn như bị cắn, cho thấy đã có người trước đó bị hại khi thử hái hoa.","theLucLienQuan":[],"nguon":["@c0423"]},{"id":"dong-phu-di-chi-tu-si-co","name":"Động phủ di chỉ tu sĩ cổ","cn":"","capDo":"khac","parentId":null,"blurb":"Di chỉ thật của tu sĩ cổ, nhưng bảo vật đã bị người khác cuỗm hết rồi mượn nơi bố trí nhiều cạm bẫy gồm Yêu Quan Xà, bạch cốt sống lại, mũi tên tà pháp.","detail":"Hàn Lập khẳng định đây là di chỉ tu sĩ cổ thật sự, tuy nhiên bảo vật bên trong đã bị người khác nhanh chân cuỗm hết từ trước. Kẻ đó sau đó mượn nơi này bố trí hàng loạt cạm bẫy: mào Yêu Quan Xà giả dạng linh thảo Thất Hà Liên, mũi tên xanh biếc ẩn hắc khí tà pháp trên bạch cốt, và thi thể bị tà thuật thao túng.","theLucLienQuan":[],"nguon":["@c0424"]},{"id":"dai-sanh-dia-dong","name":"Đại sảnh địa động","cn":"","capDo":"khac","parentId":"dong-phu-di-chi-tu-si-co","blurb":"Không gian lớn dưới lòng đất có nhiều cột đá, bậc thang dẫn lên, vách tường đá — nơi diễn ra trận chiến với quái ảnh xanh biếc và quỷ vụ.","detail":"Đại sảnh nằm trong động phủ di chỉ tu sĩ cổ, không gian rộng có nhiều cột đá (quái ảnh ẩn trong cột đá), vách tường đá (quỷ vụ phóng ra từ vách), và bậc thang dẫn lên mặt đất. Nơi Hồ Nguyệt và Thạch Điệp bị giết, nhóm Hàn Lập giao chiến với quái ảnh xanh biếc.","theLucLienQuan":[],"nguon":["@c0425"]},{"id":"cung-phung-duong","name":"Cung Phụng đường","cn":"供奉堂","capDo":"khac","parentId":null,"blurb":"Nơi trong Diệu Âm Môn treo bức hoạ chân dung các trưởng lão, đệ tử mỗi lần tới đều thấy.","detail":"Cung Phụng đường thuộc Diệu Âm Môn, treo bức hoạ chân dung trưởng lão (bao gồm Hàn Lập). Nhờ đó Văn Tư Nguyệt nhận ra Hàn Lập khi gặp ngoài môn phái.","theLucLienQuan":["Diệu Âm Môn"],"nguon":["@c0430"]},{"id":"lanh-dia-doc-long-hoi","name":"Lãnh địa Độc Long hội","cn":"","capDo":"khac","parentId":null,"blurb":"Khu vực do Độc Long hội kiểm soát, cha con Văn Tường phải đi qua để hộ tống hàng hóa cho Diệu Âm Môn.","detail":"Lãnh địa của Độc Long hội, kẻ tử địch Diệu Âm Môn. Cha con Văn Tường bị phái đi hộ tống lô hàng trân quý qua đây, bị ba tu sĩ Độc Long hội chặn đường truy đuổi.","theLucLienQuan":["Độc Long hội"],"nguon":["@c0430"]},{"id":"nam-hac-dao","name":"Nam Hạc đảo","cn":"","capDo":"khac","parentId":null,"blurb":"Hòn đảo nơi lão nho sinh Nguyên Anh kỳ (Thanh Dịch cư sĩ) xuất thân.","detail":"Nơi xuất thân của lão nho sinh lông mày trắng Nguyên Anh kỳ, được Cực Âm tổ sư chào hỏi trong đại sảnh Hư Thiên điện.","theLucLienQuan":["Nam Hạc đảo"],"nguon":["@c0432"]},{"id":"bach-bich-son","name":"Bạch Bích sơn","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi Ôn phu nhân (Nguyên Anh kỳ) xuất thân.","detail":"Nơi xuất thân của Ôn phu nhân, mỹ phụ áo trắng tu vi Nguyên Anh kỳ.","theLucLienQuan":["Bạch Bích sơn"],"nguon":["@c0432"]},{"id":"hu-thien-dien-noi-dien","name":"Hư Thiên điện — Nội điện","capDo":"khac","parentId":"hu-thien-dien","blurb":"Khu vực cực kỳ nguy hiểm bên trong Hư Thiên điện, chứa Hư Thiên đỉnh và nhiều cổ bảo. Tu sĩ Nguyên Anh kỳ vào cũng khó toàn mạng, nhiều lần mở cửa đều có người chết.","detail":"Nội điện Hư Thiên điện có mức độ nguy hiểm hoàn toàn khác ngoại điện. Tu sĩ Nguyên Anh kỳ vào cũng khó toàn mạng, nhiều lần mở cửa tầm bảo đều có Nguyên Anh kỳ chết tại đây. Tinh Cung tuyên bố không can thiệp nội điện, không cứu ai gặp nạn.","theLucLienQuan":[],"nguon":["@c0435"]},{"id":"ly-hoa-dao","name":"Ly Hỏa đảo","capDo":"khac","parentId":null,"blurb":"Nơi Cực Âm tổ sư thu được hai con hỏa mãng dị chủng.","detail":"Hải đảo nơi Cực Âm tổ sư thu phục hai con hỏa mãng dị chủng mang đến Hư Thiên điện.","theLucLienQuan":[],"nguon":["@c0435"]},{"id":"quy-vu","name":"Quỷ vụ","cn":"","capDo":"khac","parentId":"hu-thien-dien","blurb":"Cửa ải đầu tiên của Hư Thiên Điện, sương mù trắng chứa quỷ khí có thể hút tinh huyết phàm nhân biến thành xác khô.","detail":"Khu vực sương mù đậm đặc bên trong Hư Thiên Điện, là cửa ải đầu tiên phải vượt qua. Sương mù trắng dần chuyển đen khi vào sâu, chứa quỷ khí hút tinh huyết phàm nhân biến thành xác khô, hồn phách hòa vào quỷ vụ thành lệ quỷ. Mặt đất gập ghềnh, ẩm ướt. Ngọc chân nhân (Kết Đan sơ kỳ sắp lên trung kỳ) đã bị hãm chết tại đây, chứng tỏ mối nguy tiềm ẩn cực lớn.","theLucLienQuan":[],"nguon":["@c0438"]},{"id":"quy-oan-chi-dia","name":"Quỷ oan chi địa","cn":"","capDo":"khac","parentId":"quy-vu","blurb":"Khu vực trong Quỷ vụ, chia thành nhiều cửa (tầng). Cửa thứ nhất có quỷ ảnh và Quỷ Dạ Xoa canh giữ.","detail":"Người áo đen tự tin Đề Hồn thú đủ sức qua cửa thứ nhất của Quỷ oan chi địa, nhưng thực tế bị ác quỷ tách khỏi Đề Hồn thú và áp chế.","theLucLienQuan":[],"nguon":["@c0440"]},{"id":"khu-hoa-vien-co-mo","name":"Khu hoa viên trong cổ mộ","cn":"","capDo":"khac","parentId":null,"blurb":"Khu vực có kỳ hoa dị thảo và bảy tám tòa ngọc đình tinh tế nằm bên ngoài quỷ vụ trong cổ mộ, bốn phía chừng hơn trăm trượng đều là quỷ vụ đen sì cuồn cuộn vây kín. Hơn ba mươi tu sĩ tập kết tại đây sau khi vượt qua quỷ vụ.","detail":"Nơi tập kết sau khi vượt quỷ vụ: có kỳ hoa dị thảo và bảy tám tòa ngọc đình tinh tế, bốn phía bên ngoài chừng hơn trăm trượng đều là quỷ vụ đen sì cuồn cuộn bao phủ. Nhóm Nguyên Anh kỳ (Cực Âm tổ sư, Vạn Thiên Minh) ngồi riêng hai ngọc đình, hai bạch y trưởng lão Tinh Cung ngồi giữa hai nhóm.","theLucLienQuan":["Tinh Cung"],"nguon":["@c0445"]},{"id":"bang-hoa-dao","name":"Băng Hỏa đạo","cn":"","capDo":"khac","parentId":"hu-thien-dien","blurb":"Cửa ải thứ hai trong Hư Thiên Điện, đích đến của Cổ truyền tống trận lần hai, nằm sau khu vực quỷ vụ.","detail":"Trưởng lão Tinh Cung thông báo Băng Hỏa đạo là nơi tiếp theo sau quỷ vụ. Trước khi vào, tu sĩ có một ngày hái linh dược. Quá thời hạn ở lại sẽ mãi mãi không thoát — những tu sĩ còn ở lại lần mở Hư Thiên Điện trước đều biến mất không dấu vết.","theLucLienQuan":["Tinh Cung"],"nguon":["@c0447"]},{"id":"khong-gian-nho-hu-thien-dien","name":"Không gian nhỏ bên trong Hư Thiên Điện","cn":"","capDo":"khac","parentId":"hu-thien-dien","blurb":"Không gian thực do cổ tu sĩ dùng đại thần thông khai phá — bầu trời xanh mây trắng, thảo nguyên bao la, linh khí tràn trề. Nơi tu sĩ hái linh dược trước khi vào Băng Hỏa đạo.","detail":"Không gian thực (không phải ảo ảnh) với bầu trời xanh mây trắng, thảo nguyên xanh tươi bao la, đồi núi trùng điệp, hương hoa cỏ, linh khí tràn trề có hương vị trong lành đặc biệt. Huyền Cốt thượng nhân giải thích đây là sản phẩm đại thần thông cổ tu sĩ, hậu nhân không tái hiện được. Có con đường nhỏ mọc đầy cỏ dại uốn lượn dẫn tới xa.","theLucLienQuan":[],"nguon":["@c0447"]},{"id":"huyen-tinh-dao","name":"Huyền Tinh đạo","cn":"玄星道","capDo":"khac","parentId":"bang-hoa-dao","blurb":"Một trong hai thông đạo bên trong hạp cốc cửa thứ hai Băng Hỏa Lộ, băng hàn lạnh thấu xương, có thể đóng băng thân thể.","detail":"Huyền Tinh đạo là thông đạo băng hàn nằm bên trong hạp cốc bị hạ cấm chế, thuộc cửa thứ hai của Băng Hỏa Lộ. Nhiệt độ cực thấp, có thể đóng băng thân thể tu sĩ.","theLucLienQuan":[],"nguon":["@c0448","@c0463"]},{"id":"dung-nham-lo","name":"Dung Nham lộ","cn":"熔岩路","capDo":"khac","parentId":"bang-hoa-dao","blurb":"Thông đạo thứ hai trong hạp cốc cửa thứ hai Băng Hỏa Lộ, cực kỳ nóng, có thể đốt cháy người thành tro bụi.","detail":"Dung Nham lộ là thông đạo nóng cực độ nằm bên trong hạp cốc bị hạ cấm chế, thuộc cửa thứ hai của Băng Hỏa Lộ. Nhiệt độ cao đến mức có thể đốt cháy tu sĩ thành tro bụi.","theLucLienQuan":[],"nguon":["@c0448","@c0463"]},{"id":"hap-coc-cua-thu-hai-bang-hoa-lo","name":"Hạp cốc (cửa thứ hai Băng Hỏa Lộ)","cn":"峡谷","capDo":"khac","parentId":"bang-hoa-dao","blurb":"Hạp cốc bị hạ cấm chế, dài hun hút, bên trong chứa Huyền Tinh đạo và Dung Nham lộ. Đi hết sẽ gặp cổ truyền tống trận đưa ra ngoài.","detail":"Hạp cốc nằm tại cửa thứ hai Băng Hỏa Lộ, bị hạ cấm chế, bên trong và bên ngoài là hai thế giới khác nhau. Chứa hai thông đạo: Huyền Tinh đạo (băng hàn) và Dung Nham lộ (cực nóng). Cuối hạp cốc có cổ truyền tống trận có thể đưa người ra ngoài.","theLucLienQuan":[],"nguon":["@c0448"]},{"id":"tieu-thach-son","name":"Tiểu Thạch Sơn","cn":"小石山","capDo":"khac","parentId":"khong-gian-nho-hu-thien-dien","blurb":"Tòa núi đá nhỏ bình thường, không cây cỏ, linh khí ít ỏi. Nơi Cửu Khúc Linh Sâm tiềm phục.","detail":"Tiểu Thạch Sơn là một tòa núi đá nhỏ nằm trong vùng núi non trùng điệp, cách điểm truyền tống hơn hai thời thần phi hành. Bề ngoài bình thường, không có cây cỏ, linh khí ít ỏi, nhưng thực tế là nơi Cửu Khúc Linh Sâm — tiên gia bảo vật — tiềm phục bên trong đá núi. Huyền Cốt thượng nhân phát hiện nơi này khi đuổi theo Linh Cầm Thử Hổ trong lần đầu đến phiến không gian.","theLucLienQuan":[],"nguon":["@c0448"]},{"id":"noi-dien-hu-thien-dien","name":"Nội điện Hư Thiên Điện","cn":"虛天殿內殿","capDo":"khac","parentId":"hu-thien-dien","blurb":"Khu vực sâu nhất của Hư Thiên Điện, cực kỳ nguy hiểm đối với Kết Đan kỳ tu sĩ nhưng chứa bảo vật trân quý vượt xa các nơi khác.","detail":"Nội điện là khu vực trung tâm sâu nhất của Hư Thiên Điện. Cực Âm lão tổ dụ dỗ Hàn Lập vào đây, Huyền Cốt cũng thúc giục. Hàn Lập nhận định nơi này cực kỳ nguy hiểm với Kết Đan kỳ tu sĩ và kiên quyết từ chối.","theLucLienQuan":["Cực Âm Đảo"],"nguon":["@c0454","@c0493"]},{"id":"dai-hap-coc","name":"Đại hạp cốc","cn":"大峡谷","capDo":"khac","parentId":null,"blurb":"Ngọn núi lớn cao ngàn trượng toàn cự thạch xanh đen, đỉnh bị chia đôi tạo thành hẻm cốc thiên nhiên. Là lối vào Băng Hỏa đạo.","detail":"Chính giữa nơi đỉnh chia ra có hai màn hào quang hồng và lam tách biệt bao phủ mỗi nửa núi. Khoảng ba mươi tu sĩ Kết Đan tĩnh tọa chờ đợi tại lối vào, đa số Kết Đan trung-hậu kỳ.","theLucLienQuan":[],"nguon":["@c0456"]},{"id":"hac-sa-mac","name":"Hắc sa mạc","cn":"","capDo":"khac","parentId":"dai-hap-coc","blurb":"Sa mạc cát đen mênh mông bát ngát nằm trên Dung Nham lộ ở đoạn giữa hạp cốc. Diện tích rất lớn, đi đường vòng mất tối thiểu hai ngày.","detail":"Hắc sa mạc là vùng sa mạc cát đen rộng lớn nằm trên Dung Nham lộ, phía trước Hàn Lập ở đoạn giữa hạp cốc. Diện tích bao la, đi đường vòng tốn thêm tối thiểu hai ngày, gây áp lực thời gian nghiêm trọng trong giới hạn năm ngày vượt hạp cốc.","theLucLienQuan":[],"nguon":["@c0458"]},{"id":"ao-dam-dung-nham","name":"Ao đầm dung nham","cn":"","capDo":"khac","parentId":"dung-nham-lo","blurb":"Khu vực trên Dung Nham lộ, bề mặt là thực địa nhưng dung nham ngầm đánh lén. Hàn Lập nhờ Hàn Băng châu vượt qua.","detail":"Ao đầm dung nham là chướng ngại trên Dung Nham lộ, bề mặt trông như thực địa nhưng dung nham ẩn bên dưới tấn công bất ngờ. Hàn Lập nhờ Hàn Băng châu bảo vệ toàn thân mới vượt qua an toàn.","theLucLienQuan":[],"nguon":["@c0458"]},{"id":"huyet-quang-lam","name":"Huyết quang lâm","cn":"血光林","aliases":["Huyết băng lâm"],"capDo":"khac","parentId":"huyen-tinh-dao","blurb":"Khu vực trong Huyền tinh đạo, có huyết sắc băng trụ thẳng đứng, nơi cấm chế Ngân Quang Thử được kích hoạt.","detail":"Khu rừng băng trụ màu đỏ bên trong Huyền tinh đạo. Tinh Cung kích hoạt cấm chế Ngân Quang Thử tại đây, khiến mấy trăm tiểu thú bạc có sừng xuất hiện vây đánh Thanh Dịch cư sĩ.","theLucLienQuan":["Tinh Cung"],"nguon":["@c0463"]},{"id":"hu-thien-dinh","name":"Hư Thiên Đỉnh","cn":"虛天頂","capDo":"khac","parentId":"noi-dien-hu-thien-dien","blurb":"Mục tiêu mà mười tu sĩ chánh ma lưỡng đạo Kết Đan kỳ trở lên đang hướng tới bên trong Hư Thiên điện.","detail":"Đỉnh hoặc khu vực trọng yếu bên trong Hư Thiên điện. Hai trưởng lão Tinh Cung nhận định mười người chánh ma đang đi tới hướng này.","theLucLienQuan":[],"nguon":["@c0463"]},{"id":"thach-dien-truyen-tong-tran","name":"Thạch điện (truyền tống trận)","cn":"","capDo":"khac","parentId":"hac-sa-mac","blurb":"Thạch điện rộng năm sáu mươi trượng, cao bảy tám trượng, giữa có truyền tống trận để trống, cửa đá xanh đóng chặt trông như ngục tù.","detail":"Nằm trong sa mạc, nơi tập trung nhiều tu sĩ Kết Đan hậu kỳ gồm Cực Âm tổ sư, Nho Sam lão giả, Vạn Thiên Minh. Bên trong có nhiều bàn ghế đá, không khí cực kỳ căng thẳng, không ai nói với ai.","theLucLienQuan":[],"nguon":["@c0464"]},{"id":"bon-thong-dao-da-xanh","name":"Bốn thông đạo đá xanh","cn":"","capDo":"khac","parentId":"hu-thien-dien","blurb":"Bốn thông đạo mở ra từ bốn vách tường thạch điện. Ba thông đạo dẫn tới ba tòa lầu chứa Cổ bảo, Đan dược, Công pháp của thượng cổ tu sĩ; thông đạo thứ tư không có gì. Hướng đi không cố định, vào rồi không thể quay lại.","detail":"Sau khi cổ truyền tống trận biến mất, bốn vách tường thạch điện tự mở ra bốn thông đạo đá xanh. Mỗi người chỉ có một lần cơ hội lấy một thứ trong tòa lầu, lấy xong lập tức bị truyền tống tới Cực Diệu Huyễn Cảnh. Nếu không muốn đoạt bảo, ở lại thạch điện sẽ được tự động chuyển ra Hư Thiên Điện.","theLucLienQuan":["Tinh Cung"],"nguon":["@c0465"]},{"id":"cuc-dieu-huyen-canh","name":"Cực Diệu Huyễn Cảnh","cn":"","capDo":"khac","parentId":"hu-thien-dien","blurb":"Địa điểm mà tu sĩ bị truyền tống tới sau khi lấy được cổ bảo, đan dược hoặc công pháp trong tòa lầu. Chưa rõ bản chất cụ thể.","detail":"Được bạch y trưởng lão Tinh Cung tiết lộ: sau khi đoạt bảo thành công trong một trong ba tòa lầu, tu sĩ sẽ lập tức bị truyền tống tới Cực Diệu Huyễn Cảnh. Nếu không muốn đến đây, có thể chọn ở lại thạch điện để được chuyển ra Hư Thiên Điện.","theLucLienQuan":["Tinh Cung"],"nguon":["@c0465"]},{"id":"bao-quang-cac","name":"Bảo Quang Các","capDo":"khac","parentId":null,"blurb":"Toà lầu tứ giác hai tầng cao hơn 30 trượng, toàn bộ làm từ ngọc quý, lơ lửng giữa không gian hình trụ sâu thẳm, nối với vách đá bằng cầu bạch ngọc chạm rồng phượng.","detail":"Toà lầu tứ giác hai tầng, cao hơn ba mươi trượng, toàn bộ ngọc quý, biển vàng khắc ba chữ Bảo Quang Các. Tỏa linh khí kinh người, bao bọc bởi huỳnh quang trắng (cấm chế). Nằm trong không gian hình trụ phạm vi khoảng ngàn trượng, bầu trời vàng sương mù, bên dưới là vực sâu vạn trượng đen mờ ảo. Nối với vách đá bằng cầu bạch ngọc chạm rồng phượng lơ lửng giữa không trung. Đi lên từ thạch điện truyền tống trận qua cầu thang xoắn ốc bằng đá xanh hơn trăm trượng.","theLucLienQuan":[],"nguon":["@c0466"]},{"id":"thach-dien-ba-co-bao","name":"Thạch điện chứa ba cổ bảo","cn":"","capDo":"khac","parentId":"hu-thien-dinh","blurb":"Không gian trong Hư Thiên Đỉnh có cấm chế cao cấp, đặt ba cổ bảo; quy định mỗi người chỉ lấy được một, lấy xong bị truyền tống ra ngoài.","detail":"Thạch điện chứa ba cổ bảo: gương tròn màu vàng, Ngũ sắc đồng hoàn, và áo choàng lông chim đỏ sậm. Có cấm chế bảo vệ liên hệ với linh lực người vào, phát lam quang tấn công khi phát hiện ai lấy nhiều hơn một cổ bảo. Lấy xong sẽ bị truyền tống ra khu vực khác.","theLucLienQuan":[],"nguon":["@c0468"]},{"id":"thach-that-truyen-tong-hau-doan","name":"Thạch thất rộng lớn (sau thạch điện cổ bảo)","cn":"","capDo":"khac","parentId":"hu-thien-dinh","blurb":"Thạch thất rộng lớn nơi Hàn Lập bị truyền tống tới sau khi đoạt cổ bảo, có cổ truyền tống trận và một thông đạo hình vuông phía trước.","detail":"Nơi Hàn Lập xuất hiện sau khi bị cấm chế truyền tống ra khỏi thạch điện. Không gian rộng lớn, lạnh lẽo yên tĩnh lạ thường, không có ai. Chỉ có một cổ truyền tống trận và một thông đạo hình vuông duy nhất phía trước.","theLucLienQuan":[],"nguon":["@c0468"]},{"id":"huyen-canh-hac-dien","name":"Huyễn Cảnh Hắc Điện","cn":"幻境黑殿","capDo":"khac","parentId":"cuc-dieu-huyen-canh","blurb":"Tòa điện phủ đen nằm cuối hành lang Cực Diệu Huyễn Cảnh, thực chất phủ máu đọng thành sắc hồng đen, tràn ngập khí tức tà ác.","detail":"Hắc điện có đỉnh bằng, tường và cửa đều đen tuyền, khi tới gần mới phát hiện không phải hoàn toàn màu đen mà là màu hồng đen do máu nóng đọng lại, huyết khí nồng nặc xông ra. Bên trong có cấm chế đặc biệt: hấp thu mọi loại ánh sáng (hỏa cầu vừa phát liền tắt ngúm, linh thạch lấy ra mất hết sáng thành cục đá bình thường), thần thức bị phong tỏa không phóng ra được, tầm nhìn chỉ trong khoảng ba bốn trượng. Xung quanh yên tĩnh đến mức đáng sợ. Bên trong xuất hiện huyễn cảnh khai thác ký ức và tình cảm người vượt thử thách — bạch y nữ tử quỳ khóc giả dạng tiểu muội tử của Hàn Lập để tấn công tâm trí.","theLucLienQuan":[],"nguon":["@c0470"]},{"id":"noi-dien-cu-thap-da-xanh","name":"Nội điện (Cự tháp đá xanh năm tầng)","cn":"","capDo":"khac","parentId":"hu-thien-dinh","blurb":"Tòa cự tháp bằng đá xanh năm tầng nằm bên trong Hư Thiên Đỉnh, mỗi tầng cách nhau cả trăm trượng, cánh cửa cao năm sáu mươi trượng bao phủ tầng ánh sáng trắng.","detail":"Càng lên cao diện tích càng nhỏ hơn. Cánh cửa đá khổng lồ khi mở lộ ra thông đạo bằng đá xanh cực kỳ cao lớn rộng rãi. Là nơi chứa bảo vật mà chính-ma hai đạo tranh đoạt. Khi cửa mở, truyền tống trận bên ngoài thu liễm ánh sáng rồi tắt.","theLucLienQuan":[],"nguon":["@c0471"]},{"id":"me-cung-tang-mot-hu-thien-dien","name":"Mê cung tầng một Hư Thiên Điện","capDo":"khac","parentId":"hu-thien-dien","blurb":"Mê cung thông đạo bên trong Hư Thiên Điện tầng một, xếp bằng đá lớn, có cửa đá khắc phù văn và cơ quan khôi lỗi thủ vệ.","detail":"Bên trong Hư Thiên Điện là mê cung thông đạo xếp bằng đá lớn. Mỗi ngã tư có cửa đá rộng hơn mười trượng, khắc phù văn phát bạch quang (cấm chế). Có cấm chế hạn chế thần thức tu sĩ khiến không nhìn rõ thông đạo tối. Mỗi người chỉ được dùng Hư Thiên tàn đồ mở một cửa phòng lấy bảo vật, sau đó bị truyền tống ra ngoài Hư Thiên Điện. Tu sĩ Kết Đan kỳ chỉ lấy được bảo vật tầng một, lên tầng cao hơn chẳng khác tự sát. Có cơ quan khôi lỗi thủ vệ gồm bốn khôi lỗi cấp A và khôi lỗi lang thủ kim sắc.","theLucLienQuan":[],"nguon":["@c0473"]},{"id":"noi-dien-hu-thien-tang-hai","name":"Nội điện Hư Thiên — Tầng hai","cn":"","capDo":"khac","parentId":"noi-dien-hu-thien-dien","blurb":"Tầng hai nội điện Hư Thiên Điện, cấu trúc tương tự tầng một nhưng ít ngã tư hơn, khoảng cách dài hơn, có cấm chế và bẫy rập lợi hại cùng cơ quan Xà vệ Khôi lỗi thủ vệ.","detail":"Nhóm ma đạo truyền tống từ tầng một lên qua Truyền tống trận nhỏ giữa ngã tư. Tầng hai có cấu trúc ngã tư và thông đạo tương tự tầng một nhưng ít ngã tư hơn, khoảng cách dài hơn. Xuất hiện cấm chế và bẫy rập lợi hại — đối với tu sĩ Kết Đan kỳ cực kỳ nguy hiểm. Cơ quan thủ vệ là Xà vệ Khôi lỗi, mạnh hơn nhiều so với Khôi lỗi Lang thú tầng một. Mục tiêu nhóm ma đạo: nhanh chóng vượt qua để đến tầng năm tranh đấu với phe chính đạo.","theLucLienQuan":[],"nguon":["@c0474"]},{"id":"truyen-tong-tran-tang-mot-len-tang-hai","name":"Truyền tống trận (tầng một → tầng hai)","cn":"","capDo":"khac","parentId":"noi-dien-hu-thien-dien","blurb":"Truyền tống trận nhỏ nằm chính giữa ngã tư đường tầng một, tản ánh sáng nhạt, dùng để truyền tống lên tầng hai.","detail":"Nằm chính giữa ngã tư đường tầng một nội điện Hư Thiên Điện, tỏa ánh sáng nhạt. Man Hồ Tử phá hủy bảy tám cơ quan Khôi lỗi dọc đường rồi đưa nhóm đến trước trận này. Nhóm chính đạo Vạn Thiên Minh đã đi qua trước.","theLucLienQuan":[],"nguon":["@c0474"]},{"id":"thach-dai-tang-nam","name":"Thạch đài tầng năm","cn":"","capDo":"khac","parentId":"noi-dien-hu-thien-dien","blurb":"Thạch đài khổng lồ rộng trăm trượng, cao hơn ba mươi trượng tại tầng năm nội điện Hư Thiên Điện, bao phủ bởi Thiên cương tráo cấm chế thượng cổ, chỉ có một lối ra duy nhất.","detail":"Thạch đài khổng lồ rộng trăm trượng, cao hơn ba mươi trượng, phía trước có mấy trăm bậc thềm đá. Bên ngoài bao phủ màn hào quang trắng có lam quang lấp lòe chính là Thiên cương tráo cấm chế thượng cổ, chỉ có một lối ra vào duy nhất. Hai bên bờ đài ngưng kết băng sương dày trong suốt. Mặt sau có vách tường đá khắc văn tự và hình quái thú thượng cổ kèm cấm chế cao thâm, trong đó có khối đá thứ ba khắc hình yêu thú có cánh mắt đỏ như máu bên trong trống rỗng chứa vật bí ẩn.","theLucLienQuan":[],"nguon":["@c0475"]},{"id":"te-dan-trung-tam-dai-cao","name":"Tế đàn trung tâm đài cao","capDo":"khac","parentId":"thach-dai-tang-nam","blurb":"Tế đàn nhỏ nằm ở trung tâm thạch đài tầng năm, bao phủ bởi màn hào quang, nơi Kim Ti Tằm đang phun tơ kéo vật từ cái động tỏa lam quang.","detail":"Tế đàn nằm tại trung tâm đài cao bên trong màn hào quang bảo hộ. Trên đó có bảy tám đạo kim quang lay động, giữa đó là cái động lớn tỏa lam quang chói mắt nơi Kim Ti Tằm bích lục phun sợi tơ vàng kéo vật. Ba tu sĩ chính đạo (nhóm Vạn Thiên Minh) canh giữ tại đây.","theLucLienQuan":[],"nguon":["@c0476"]},{"id":"day-dong-hu-thien-dinh","name":"Đáy động chứa Hư Thiên đỉnh","cn":"","capDo":"khac","parentId":"te-dan-trung-tam-dai-cao","blurb":"Hố động sâu khoảng 20-30 trượng bên dưới tế đàn, đáy có Kiền Lam Băng Diễm thiêu đốt bao bọc Hư Thiên đỉnh, tản ra kỳ hàn thấu xương.","detail":"Hố động sâu khoảng hai ba mươi trượng nằm bên dưới tế đàn trung tâm đài cao. Đáy động có luồng lửa lam Kiền Lam Băng Diễm đang thiêu đốt, bên trong lửa có Hư Thiên đỉnh màu đen chớp động. Kỳ hàn thấu xương tản ra từ trong động, tu sĩ Kết đan kỳ cần có vật bảo hộ mới chịu nổi. Khi kéo đỉnh, tế đàn chớp động, lam quang loé lên gây hoa mắt.","theLucLienQuan":[],"nguon":["@c0478"]},{"id":"hac-dien-cuc-dieu-huyen-canh","name":"Hắc điện (Cực Diệu Huyễn Cảnh)","cn":"","capDo":"khac","parentId":"cuc-dieu-huyen-canh","blurb":"Tòa điện phủ đen tuyền nằm cuối hành lang Cực Diệu Huyễn Cảnh, đỉnh bằng, cao mười trượng, tường và cửa phủ lớp máu khô hồng đen. Bên trong tràn ngập huyết khí, cấm chế hấp thu mọi ánh sáng và phong tỏa thần thức, là nơi diễn ra khảo nghiệm tâm cảnh ác liệt nhất — tấn công vào tình cảm sâu kín nhất.","detail":"Tòa hắc điện nằm ở cuối hành lang Cực Diệu Huyễn Cảnh, cao khoảng mười trượng, đỉnh bằng phẳng, toàn bộ tường và cửa đen tuyền. Màu đen thực ra là màu hồng đen do máu khô đọng lại dày đặc, xung quanh tràn ngập huyết khí nồng nặc và khí tức tà ác. Bên trong có cấm chế thần kỳ hấp thu tất cả các loại ánh sáng: hỏa cầu bị dập tắt lập tức, linh thạch mất quang trở thành cục đá thường. Thần thức cũng bị phong tỏa, chỉ nhìn được ba bốn trượng, yên tĩnh tuyệt đối đến đáng sợ. Khảo nghiệm bên trong không dùng mỹ sắc mà tấn công thẳng vào ký ức và tình cảm gia đình — điểm yếu chí mạng nhất.","theLucLienQuan":[],"nguon":["@c0470"]},{"id":"truyen-tong-tran-truoc-noi-dien","name":"Truyền tống trận (trước Nội điện)","capDo":"khac","parentId":"day-dong-hu-thien-dinh","blurb":"Truyền tống trận nằm giữa nhóm tu sĩ trước cự tháp Nội điện, lấp lánh ánh sáng trắng. Sau khi cửa Nội điện mở, truyền tống trận thu liễm bạch quang trở nên ảm đạm, cắt đường truyền tống.","detail":"Nằm trước tòa cự tháp đá xanh năm tầng (Nội điện Hư Thiên Đỉnh). Hàn Lập và Nguyên Dao đều đến nơi qua truyền tống trận này. Sau khi cánh cửa đá khổng lồ Nội điện mở ra, truyền tống trận thu liễm ánh sáng và trở nên ảm đạm — hai trưởng lão Tinh Cung và một tu sĩ Kết Đan hậu kỳ không kịp đến.","theLucLienQuan":[],"nguon":["@c0471"]},{"id":"thach-dai-tang-nam-noi-dien","name":"Thạch đài tầng năm nội điện","cn":"","capDo":"khac","parentId":"noi-dien-hu-thien-dien","blurb":"Thạch đài khổng lồ tại tầng năm nội điện thượng cổ, rộng trăm trượng, cao hơn ba mươi trượng, bao phủ bởi Thiên cương tráo cấm chế.","detail":"Thạch đài khổng lồ nằm ở tầng năm nội điện thượng cổ, rộng trăm trượng, cao hơn ba mươi trượng. Phía trước có mấy trăm bậc thềm đá. Bên ngoài bao phủ bởi Thiên cương tráo cấm chế tạo màn hào quang trắng, bên trong có lam quang lấp lòe mạnh dần về trung tâm, hai bên bờ đài ngưng kết băng sương dày trong suốt. Phía sau là vách tường đá điêu khắc văn tự và hình quái thú thượng cổ, thiết lập cấm chế cao thâm mà tu sĩ Nguyên Anh kỳ cũng không phá nổi. Chỉ có một lối ra vào duy nhất.","theLucLienQuan":[],"nguon":["@c0475"]},{"id":"tang-thu-nam-hu-thien-dien","name":"Tầng thứ năm Hư Thiên điện","cn":"","capDo":"khac","parentId":"hu-thien-dinh","blurb":"Tầng thứ năm bên trong Hư Thiên điện, nơi chân thân hai trưởng lão Tinh Cung ẩn nấp khoanh chân ngồi trong bóng tối.","detail":"Vị trí ẩn mình của chân thân hai trưởng lão Tinh Cung trong khi phân thân Hóa Thân Phù hoạt động ở nội điện phía dưới. Hai người ngồi trong bóng tối bàn luận về Bổ Thiên Đan rồi rời đi.","theLucLienQuan":["Tinh Cung"],"nguon":["@c0484"]},{"id":"huyen-am-dao","name":"Huyền Âm đảo","cn":"玄阴岛","capDo":"khac","parentId":null,"blurb":"Hòn đảo nơi Việt Hoàng có được công pháp, Hàn Lập nghi ngờ có liên quan đến Cực Huyễn.","detail":"Hàn Lập nhắc đến trong suy nghĩ khi nghe Huyền Cốt tiết lộ về Cực Huyễn, nghi vấn công pháp Việt Hoàng từ Huyền Âm đảo có liên hệ gì với Cực Huyễn.","theLucLienQuan":[],"nguon":["@c0487","@c0526"]},{"id":"dai-cao-thuong-co-thien-cuong","name":"Đài cao thượng cổ thiên cương","capDo":"khac","parentId":"hu-thien-dinh","blurb":"Đài cao danh tiếng lẫy lừng từ thời thượng cổ, có đặc tính che chắn: bên trong dù thiên băng địa liệt, bên ngoài chỉ có thể dùng mắt nhìn thấy, thần thức không thể cảm ứng bất kỳ điều gì dị thường.","detail":"Đài cao nằm trong khu vực Hư Thiên Đỉnh, có đặc tính thượng cổ thiên cương che chắn hoàn toàn thần thức. Bên ngoài người ta chỉ có thể dùng nhục nhãn quan sát, không thể dùng thần thức để cảm ứng các biến động bên trong. Huyền Cốt lợi dụng đặc tính này để liên thủ với Hàn Lập kéo bảo đỉnh mà không bị phát hiện.","theLucLienQuan":[],"nguon":["@c0488"]},{"id":"truyen-tong-tran-hu-thien-dien","name":"Truyền Tống trận (biên nội điện Hư Thiên điện)","cn":"","capDo":"khac","parentId":"noi-dien-hu-thien-dien","blurb":"Truyền Tống trận nằm sau bức tường cao ở biên nội điện Hư Thiên điện, là điểm cuối của lộ tuyến đỏ trên quyển trục cổ. Chưa xác nhận thực tế có còn hoạt động hay không.","detail":"Theo tiêu ký trên quyển trục cổ, điểm cuối lộ tuyến đỏ có tiêu ký giống Truyền Tống trận, nằm sau bức tường cao ở biên nội điện tầng năm. Hàn Lập quyết định đi theo lộ tuyến này nhưng chưa đến nơi xác nhận.","theLucLienQuan":[],"nguon":["@c0493"]},{"id":"mat-that-truyen-tong-tran-noi-dien","name":"Mật thất chứa Truyền Tống trận","cn":"","capDo":"khac","parentId":"noi-dien-hu-thien-dien","blurb":"Gian phòng nhỏ ẩn sau bức tường không cấm chế trong nội điện Hư Thiên điện, chứa Truyền Tống trận thô sơ.","detail":"Mật thất nhỏ cao hai trượng, dài rộng sáu bảy trượng, phủ đầy bụi, nằm sau một bức tường cao bình thường không có cấm chế. Giữa phòng có một tòa Truyền Tống trận thô sơ xiên xẹo. Hàn Lập theo bản đồ mực đỏ trên quyển trục cũ kỹ tìm đến, phá tường vào rồi trám lại lỗ thủng trước khi kích hoạt trận truyền tống đi.","theLucLienQuan":[],"nguon":["@c0494"]},{"id":"thach-that-ho-linh-nhan-chi-tuyen","name":"Thạch thất chứa hồ Linh nhãn chi tuyền","cn":"","capDo":"khac","parentId":"noi-dien-hu-thien-dien","blurb":"Thạch thất rộng lớn trong nội điện Hư Thiên điện, chứa hồ Linh nhãn chi tuyền trắng sữa rộng vài chục trượng.","detail":"Thạch thất rộng ba bốn chục trượng, không khí ẩm ấm tỏa hương thơm thoang thoảng, hai bên có cửa đá. Giữa phòng là hồ nước trắng sữa rộng vài chục trượng chứa Linh nhãn chi tuyền với linh khí tinh thuần. Trên tường đá phía sau có phù điêu hình đầu rồng bằng bạch ngọc, phía dưới lõm đặt bình ngọc xanh đang hứng chất lỏng. Chủ nhân Hư Thiên điện đã chuyển dời cả dòng linh tuyền lớn đến đây.","theLucLienQuan":[],"nguon":["@c0494"]},{"id":"mat-that-tang-hai-noi-dien-hu-thien-dien","name":"Mật thất tầng hai nội điện Hư Thiên điện","cn":"","capDo":"khac","parentId":"noi-dien-hu-thien-dien","blurb":"Khu vực bên dưới mật thất tầng một trong nội điện Hư Thiên điện, gồm ít nhất hai gian thạch ốc nối nhau, chứa linh tuyền cổ đại và Dưỡng Hồn mộc sau cấm chế.","detail":"Gian trong có linh tuyền (nơi phun đầu rồng) — linh tuyền tích lũy vạn năm sản sinh Vạn niên linh nhũ. Gian ngoài lớn hơn, có dấu vết khổ chiến với khôi lôi bị phá hủy. Đối diện có thạch môn phủ cấm chế bạch quang (cùng hệ thống cấm chế tầng 1 đến tầng 5), che giấu Dưỡng Hồn mộc bên trong. Có lối ra phía bắc. Hư Thiên tàn đồ không thể mở cấm chế từ bên trong.","theLucLienQuan":[],"nguon":["@c0495"]},{"id":"mat-bien-ngoai-hu-thien-dien","name":"Mặt biển bên ngoài Hư Thiên điện","capDo":"khac","parentId":"loan-tinh-hai","blurb":"Vị trí Hàn Lập và Nguyên Dao bị truyền tống ra sau khi phá trận trong mật thất, cách Hư Thiên điện vài chục dặm.","detail":"Vùng mặt biển bên ngoài Hư Thiên điện, nơi Truyền Tống trận đưa hai người ra. Nguyên Dao giải thích vị trí truyền tống ngẫu nhiên, có thể gần hoặc xa vài trăm dặm, các lão quái Nguyên Anh kỳ không thể giám sát phạm vi rộng lớn như vậy.","theLucLienQuan":[],"nguon":["@c0496"]},{"id":"nam-minh-dao","name":"Nam Minh đảo","cn":"","capDo":"khac","parentId":"loan-tinh-hai","blurb":"Điểm trung chuyển cuối cùng trước Thiên Tinh thành, có nhóm tu sĩ Tinh Cung đồn trú trấn thủ.","detail":"Hải đảo diện tích không lớn, là trạm gác ngoại vi của Tinh Cung. Cảng khẩu có đại trận bảo vệ phát hào quang đỏ. Phường thị nằm trong tòa tiểu thành gần cảng, hàng hóa đầy đủ và giá rẻ hơn Thiên Tinh thành vì hàng bốc dỡ trực tiếp tại đây. Cảng vắng vẻ hơn bình thường do đại chiến sắp đến — chỉ còn hơn mười thuyền nhỏ. Bị Nghịch Tinh minh tấn công, đại chiến nổ ra tại đây.","theLucLienQuan":["Tinh Cung","Nghịch Tinh minh"],"nguon":["@c0499"]},{"id":"ben-cang-nam-minh-dao","name":"Bến cảng Nam Minh đảo","cn":"","capDo":"khac","parentId":"nam-minh-dao","blurb":"Bến cảng trên Nam Minh đảo, nơi diễn ra trận chiến giữa Nghịch Minh Tinh và Tinh Cung. Sau trận, rơi vào tay Nghịch Minh Tinh và trở thành bàn đạp tiến công Thiên Tinh Thành.","detail":"Bến cảng chính của Nam Minh đảo, từng được Tinh Cung bố trí đại trận phòng thủ hồng quang. Bị liên thủ chính ma lưỡng đạo của Nghịch Minh Tinh phá vỡ. Sau trận, Nghịch Minh Tinh bố trí đại trận ngụy trang mới, biến nơi đây thành căn cứ kiểm soát và bàn đạp quân sự.","theLucLienQuan":["Nghịch Tinh minh","Tinh Cung"],"nguon":["@c0500"]},{"id":"tang-thu-tu-thanh-son","name":"Tầng thứ tư Thánh sơn","cn":"","capDo":"khac","parentId":"thanh-son","blurb":"Khu vực trên Thánh sơn nơi nhóm 7 tu sĩ Trúc Cơ cư trú trong trạch viện bình thường, phụ cận có mấy khu sân và rừng trúc bích lục nhỏ, không khí u tĩnh.","detail":"Hàn Lập bám theo hai tu sĩ tới đây, vượt trận pháp Lưu thủy trận lẻn vào trạch viện nghe trộm cuộc bàn bạc của nhóm.","theLucLienQuan":["Tinh Cung"],"nguon":["@c0506"]},{"id":"tinh-khong-dien","name":"Tinh Không điện","cn":"","capDo":"khac","parentId":"thanh-son","blurb":"Còn gọi Thiên Môn đại điện, nơi Trương đạo hữu tới đàm phán chuyện truyền tống lén ra Ngoại Tinh hải.","detail":"Hàn Lập bám theo hán tử cao gầy tới đây, đợi nửa thời thần rồi thấy hắn ra với vẻ hưng phấn.","theLucLienQuan":["Tinh Cung"],"nguon":["@c0506"]},{"id":"ky-uyen","name":"Kỳ Uyên","cn":"奇渊","capDo":"khac","parentId":null,"blurb":"Địa danh ghi trên tấm bia phía trước Truyền tống trận, là đích đến truyền tống từ Tinh Không Điện. Hàn Lập không có chút ấn tượng gì về nơi này.","detail":"Tên ghi trên bia trước Truyền tống trận trong điện, là điểm đến khi truyền tống ra Ngoại Tinh Hải. Hàn Lập hoàn toàn xa lạ với địa danh này.","theLucLienQuan":[],"nguon":["@c0508"]},{"id":"hac-thach-thanh","name":"Hắc Thạch thành","cn":"黑石城","capDo":"thanh","parentId":"ky-uyen-dao","blurb":"Tòa thành duy nhất trên Kỳ Uyên Đảo, toàn bộ xây bằng đá đen, phương viên hơn hai mươi dặm, nghiêm cấm đấu pháp và luôn có tu sĩ Nguyên Anh Kỳ tọa trấn.","detail":"Tòa thành duy nhất trên Kỳ Uyên Đảo, toàn bộ xây bằng đá đen, phương viên hơn hai mươi dặm. Truyền tống trận nằm ở trung tâm trên đài giống tế đàn. Tường đá cao ba bốn trượng, bên ngoài có hào quang trắng bao trùm. Trong thành tu sĩ và người thường xen lẫn, đặc biệt nhiều nữ tử xinh đẹp ăn mặc hoa lệ và nam tử cường tráng. Nghiêm cấm đấu pháp, vi phạm sẽ bị hình thần câu diệt — trừng phạt nghiêm hơn Thiên Tinh thành. Chưa từng có ai vi phạm mà sống sót trốn khỏi thành. Là thiên đường mua sắm: Song tu lô đỉnh cấp, pháp bảo uy lực cường đại, linh thú giá trị liên thành, tài liệu trăm năm khó tìm đều có bán.","theLucLienQuan":["Thế lực thống trị Kỳ Uyên Đảo"],"nguon":["@c0510","@c0525"]},{"id":"ky-uyen-dao","name":"Kỳ Uyên Đảo","cn":"","capDo":"khac","parentId":null,"blurb":"Hòn đảo nơi Hắc Thạch thành tọa lạc, bị một thế lực cường đại bí ẩn thống trị. Tin tức trước đây về đảo hầu hết là ngụy tạo.","detail":"Hòn đảo khác với Yêu Thú đảo mà các tu sĩ tưởng mình sẽ đến. Bị một thế lực cường đại thống trị, ngay cả Tinh Cung cũng không dễ đắc tội. Tu sĩ rời đảo đều bị ép tiết lộ cùng một loại tin tức giả, nên thông tin bên ngoài về đảo hầu hết là ngụy tạo.","theLucLienQuan":["Thế lực thống trị Kỳ Uyên Đảo"],"nguon":["@c0510"]},{"id":"hai-uyen-yeu-thu","name":"Hải uyên yêu thú","cn":"","capDo":"khac","parentId":"ky-uyen-dao","blurb":"Toà hải uyên (vực sâu) ở hải vực phụ cận Kỳ Uyên đảo, sâu không lường được, thường xuyên xuất hiện yêu thú cấp cao.","detail":"Hải vực phụ cận Kỳ Uyên đảo chứa một toà hải uyên sâu không lường. Thường xuất hiện yêu thú cấp bảy, thậm chí có tin đồn yêu thú ngoài cấp tám (tương đương Nguyên Anh Kỳ) từng lộ diện. Dễ tìm yêu thú hơn hải vực bình thường nhưng nguy hiểm tương ứng. Là nguyên nhân chính khiến nhiều thế lực tranh giành Kỳ Uyên đảo và từng đại chiến với tứ đại thương minh.","theLucLienQuan":["Liên minh thế lực Kỳ Uyên đảo","Tứ đại thương minh","Tinh Cung"],"nguon":["@c0511"]},{"id":"minh-chau-hien-noi-bo","name":"Minh Châu hiên","cn":"","capDo":"khac","parentId":"ky-uyen-dao","blurb":"Cơ sở kinh doanh trên Kỳ Uyên đảo do Minh phu nhân quản lý, bên trong chia Giám Bảo thính và Bảo thính.","detail":"Bên trong chia hai đại sảnh: trái là Giám Bảo thính (nơi tu sĩ xếp hàng giám định đổi đồ lấy linh thạch, mỗi lần vào một người, có nữ tử phàm nhân bồi tiếp), phải là Bảo thính (phòng đấu giá, che bởi hào quang lam nhạt, phàm nhân không được phép vào, bên trong có thạch đài đấu giá).","theLucLienQuan":["Minh Châu hiên"],"nguon":["@c0511"]},{"id":"phong-dau-gia-hac-thach-thanh","name":"Phòng đấu giá Hắc Thạch thành","cn":null,"capDo":"khac","parentId":"hac-thach-thanh","blurb":"Phòng đấu giá thường xuyên tổ chức tại Hắc Thạch thành, mấy ngày nửa tháng một lần, có vài loại vật phẩm đặc thù mà ở Nội Tinh Hải khó tìm, bao gồm trứng yêu thú và lô đỉnh nữ tu.","detail":"Phòng đấu giá nằm trong Hắc Thạch thành trên Kỳ Uyên đảo, tổ chức thường xuyên mấy ngày nửa tháng một lần. Nơi đây bán trứng yêu thú (đặc sản không thể truyền tống), cũng công khai đấu giá nữ tu lô đỉnh — điều mà ở Nội Tinh Hải không xảy ra.","theLucLienQuan":["Thế lực quản lý Hắc Thạch thành"],"nguon":["@c0512"]},{"id":"thon-kim-cac-hac-thach-thanh","name":"Thốn Kim Các","cn":"","capDo":"khac","parentId":"hac-thach-thanh","blurb":"Cửa hàng nguyên liệu lớn nhất Hắc Thạch thành, nằm trên ngã tư đường gần Minh Châu hiên.","detail":"Bề ngoài giống nhà đá to lớn, bên trong chia nhiều gian nhỏ chuyên bán các loại nguyên liệu khác nhau, có gian khách quý riêng tiếp tu sĩ Kết Đan trở lên.","theLucLienQuan":["Thốn Kim Các"],"nguon":["@c0513"]},{"id":"hai-uyen","name":"Hải Uyên","cn":"","capDo":"vuc","parentId":"ngoai-tinh-hai","blurb":"Vùng biển rộng lớn cách Kỳ Uyên đảo không xa, diện tích cực lớn, chưa ai dò được độ sâu, nơi tụ tập rất nhiều tu sĩ.","detail":"Cách Kỳ Uyên đảo nửa tháng bay tốc độ cao nhất. Diện tích cực lớn, chưa ai dò được độ sâu. Là nơi tụ tập của rất nhiều tu sĩ. Hàn Lập chọn bay về phía Bắc để tránh xa Hải Uyên.","theLucLienQuan":[],"nguon":["@c0515"]},{"id":"hoang-dao-suong-mu","name":"Hoang đảo sương mù","cn":"","aliases":["Vụ Trung Đảo","Vụ hải tiểu đảo"],"capDo":"khac","parentId":"ngoai-tinh-hai","blurb":"Hoang đảo không người ở phía Tây Bắc Kỳ Uyên đảo, bị sương trắng bao phủ do đàn Thôn Hải Ngư phun sương. Hàn Lập chọn làm nơi xây động phủ mới.","detail":"Hoang đảo thứ tư có linh mạch mà Hàn Lập tìm được, nằm phía Tây Bắc Kỳ Uyên đảo. Có linh mạch nhỏ nhưng linh khí bậc trung, sung túc. Địa hình phức tạp gồm hoang địa, rừng cây, đồng cỏ hoa lá, mấy ngọn núi nhỏ (cao ba bốn trượng), linh mạch dài hơn mười trượng. Đàn Thôn Hải Ngư (yêu thú bậc một, cá không vảy toàn gai xương bạc) sống dưới đáy đảo nuốt nước biển phun sương, tạo màn sương trắng bao phủ toàn đảo. Hàn Lập phát hiện đảo nhờ truy đuổi Ngân Dực Điểu (yêu thú cấp bốn) bay vào sương. Sau đó xây động phủ trong lòng núi tại tiểu cốc, bố trận ảo giác và trận pháp sương mù nhân tạo phòng thủ.","theLucLienQuan":[],"nguon":["@c0515"]},{"id":"trung-that-dong-phu","name":"Trùng thất (động phủ Hàn Lập)","capDo":"khac","parentId":"hoang-dao-suong-mu","blurb":"Năm gian thạch thất lớn nhỏ khác nhau trong động phủ hiện tại của Hàn Lập, dùng nuôi các loại yêu trùng và yêu thú.","detail":"Gồm năm gian thạch thất: hai gian nuôi Phệ Kim Trùng (nhóm mấy vạn con và nhóm mấy ngàn con tinh chọn), một gian nuôi Huyết Ngọc Tri Thù, một gian chứa Đề Hồn Thú, gian cuối nuôi Kim Ti Tằm. Đơn giản hơn so với trùng thất ở Thiên Tinh Thành.","nguon":["@c0516"]},{"id":"duoc-vien-dong-phu","name":"Dược viên (động phủ Hàn Lập)","capDo":"khac","parentId":"hoang-dao-suong-mu","blurb":"Khu vực trồng dược liệu trong động phủ Hàn Lập, trung tâm có trận kỳ cấm chế che chắn để trồng Cửu Khúc Linh Sâm.","detail":"Hàn Lập kiến lập tầng đất bao phủ ở trung tâm dược viên, thiết lập trận kỳ cấm chế che chắn kỹ càng, bên ngoài trông như tảng đá lớn màu vàng. Cửu Khúc Linh Sâm được trồng bên trong.","nguon":["@c0516"]},{"id":"hai-vuc-phu-can-van-vu","name":"Hải vực phụ cận vân vụ","cn":"","capDo":"khac","parentId":"ngoai-tinh-hai","blurb":"Khu vực biển gần nơi Hàn Lập có động phủ trong vân vụ, nơi cự quy độ kiếp và xảy ra đại chiến Độc Giao vs ba tu sĩ.","detail":"Khu vực biển phụ cận hoang đảo sương mù (động phủ Hàn Lập). Tại đây cự quy độ Hóa Hình Lôi Kiếp, Độc Giao xuất hiện bảo vệ và giao chiến với Kim Hà đạo sĩ cùng Hoắc thị huynh đệ. Sau trận chiến, hải vực trở lại sóng yên biển lặng, Hàn Lập quay lại lặn xuống nhặt được một món đồ.","theLucLienQuan":[],"nguon":["@c0519"]},{"id":"mang-san-ho-do","name":"Mảng san hô đỏ","cn":"","capDo":"khac","parentId":"ngoai-tinh-hai","blurb":"Mảng san hô đỏ phía tây vụ hải, cách động phủ Hàn Lập một tháng bay, nơi Hàn Lập bày trận dụ yêu bằng Nghê Thường Thảo.","detail":"Nằm cách xa Hoang đảo sương mù về phía tây, Hàn Lập dừng lại tại đây sau một tháng bay để tránh phiền toái. Bày bốn pháp trận vây kín, trồng Nghê Thường Thảo ở trung tâm dụ yêu thú cấp năm và cấp sáu. Là nơi Hàn Lập lần đầu hoàn thành quy trình trừu hồn thủ đan.","theLucLienQuan":[],"nguon":["@c0521"]},{"id":"tham-uyen","name":"Thâm uyên","cn":"","capDo":"khac","parentId":"ngoai-tinh-hai","blurb":"Hải vực nguy hiểm có yêu thú ngoài cấp tám lui tới và tu sĩ tụ tập đông, Hàn Lập không đến vì đã có Nghê Thường Thảo.","detail":"Hải vực nguy hiểm nơi có yêu thú ngoài cấp tám và nhiều tu sĩ tụ tập. Hàn Lập quyết định không tới vì đã có Nghê Thường Thảo làm phương tiện dụ yêu, tránh chỗ đông người phiền toái.","theLucLienQuan":[],"nguon":["@c0521"]},{"id":"ky-duyen-dao-hai-vuc","name":"Kỳ Duyên Đảo (hải vực)","cn":"奇缘岛","capDo":"vuc","parentId":"ngoai-tinh-hai","blurb":"Khu vực hải vực thuộc Ngoại Tinh Hải, nơi Hàn Lập đang hoạt động. Trước kia ít tu sĩ lui tới, nay đông hơn do thâm uyên trở thành vùng cấm.","detail":"Hải vực xung quanh Kỳ Duyên Đảo, nằm trong Ngoại Tinh Hải. Sau khi thâm uyên kinh biến hai năm trước (yêu thú phát cuồng, giết cả tu sĩ Nguyên Anh kỳ), tu sĩ dồn ra hải vực bên ngoài khiến khu vực này đông đúc hơn trước. Trùng Ma cũng hoạt động quanh hải vực này, liên tục giết tu sĩ đoạt bảo.","theLucLienQuan":[],"nguon":["@c0524"]},{"id":"tieu-son-coc-dong-phu","name":"Tiểu sơn cốc (động phủ nam tử thần bí)","cn":"","capDo":"khac","parentId":"hoang-dao-suong-mu","blurb":"Động phủ ẩn trong sơn cốc trên đảo sương mù, nơi Công Tôn Hạnh bị truyền tống đến. Hai sườn núi đá, có thạch môn xanh cao mấy trượng, bên trong nhiều phòng với cự viên Khôi Lỗi canh gác, hoa viên nhỏ và phòng chứa ngọc giản tri thức.","detail":"Tiểu sơn cốc xa lạ, hai bên là sườn núi đá, phía trước có cửa đá màu xanh cao mấy trượng. Bên trong động phủ có đại sảnh nhiều cánh cửa, mỗi cửa do cự viên Khôi Lỗi canh giữ. Một số cửa bị chặn không cho vào, một số cửa được tự do đi qua. Qua hoa viên nhỏ có phòng chứa ngọc giản đủ màu xếp trên thạch đài, nội dung đa dạng (trận pháp, đạo luyện khí). Có thạch thất chứa giường, bàn đá, ghế đá để ở.","theLucLienQuan":[],"nguon":["@c0530"]},{"id":"phuong-thi-tieu-hoang-dao","name":"Phường thị tiểu hoang đảo (hướng Nam)","cn":"","capDo":"khac","parentId":"loan-tinh-hai","blurb":"Phường thị trên tiểu hoang đảo cách đảo Hàn Lập nửa tháng lộ trình về hướng Nam, do mấy vị Kết Đan kỳ tiền bối liên thủ thành lập.","detail":"Nơi tu sĩ phụ cận đều tới trao đổi vật phẩm, tương đối an toàn. Công Tôn Hạnh cho Hàn Lập biết vị trí này khi hắn hỏi thăm nơi mua bán trong hải vực.","theLucLienQuan":[],"nguon":["@c0531"]},{"id":"nam-le-dao-phuong-thi","name":"Nam Lê Đảo phường thị","cn":"","capDo":"thanh","parentId":"ngoai-tinh-hai","blurb":"Phường thị trên hòn đảo nhỏ tại Ngoại Tinh hải, đã bị yêu thú cấp bốn, năm tấn công phá hủy.","detail":"Phường thị mà Hàn Lập đang hướng tới sau khi xuất quan. Mấy ngày trước bị yêu thú cấp thấp phát hiện, ngày hôm sau yêu thú cấp bốn, năm kéo đến tấn công, tu sĩ tổn thương nặng buộc phải chia nhau phá vây chạy thoát.","theLucLienQuan":[],"nguon":["@c0532"]},{"id":"bi-thi","name":"Bí thị","cn":"","capDo":"khac","parentId":null,"blurb":"Phường thị bí mật dành cho tu sĩ trên Trúc Cơ Kỳ, cần người quen dẫn đường, địa điểm thường xuyên thay đổi, hàng hóa đều là trân phẩm.","detail":"Phường thị bí mật mà Hoàng Minh Lễ biết và dẫn Hàn Lập tới. Chỉ tu sĩ đã ngoài Trúc Cơ Kỳ mới có thể vào, cần người quen dẫn đường, địa điểm thường xuyên thay đổi. Cách vị trí hiện tại hơn nửa tháng đường, vừa kịp lúc khai thị.","theLucLienQuan":[],"nguon":["@c0532"]},{"id":"dao-nho-phuong-thi-bi-an","name":"Đảo nhỏ (phường thị bí ẩn)","cn":"","capDo":"khac","parentId":"ngoai-tinh-hai","blurb":"Hòn đảo hơn trăm dặm nằm ở hướng đông ngoài hải vực, linh khí ít ỏi, phần lớn nham thạch xám. Bên dưới có không gian ngầm khổng lồ dùng làm phường thị.","detail":"Đảo nhỏ linh khí ít, ít cây cối, chủ yếu nham thạch xám. Cách nơi Hàn Lập xuất phát nửa tháng bay về hướng đông. Không bố trí cấm chế trên mặt đảo, nhập đảo bằng cách gõ tảng đá ba cái mở ra động khẩu. Bên trong có phường thị ngầm nhiều tầng dùng Thạch Hóa thuật tạo thành.","theLucLienQuan":["Phường thị bí ẩn (đảo nhỏ)"],"nguon":["@c0533"]},{"id":"dia-diem-giao-hoan-hoi","name":"Địa điểm Giao hoán hội (của Vân Thiên Khiếu)","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi tổ chức Giao hoán hội bí mật giữa các tu sĩ Kết Đan kỳ, do Vân Thiên Khiếu làm chủ. Nằm sau cửa đá ẩn trong vách tường, bên trong có thông đạo dẫn tới đại sảnh hình vuông với bàn tròn lớn và hơn chục ghế.","detail":"Bên trong có đại sảnh hình vuông với bàn tròn lớn và hơn chục chiếc ghế xếp xung quanh. Tu sĩ Kết Đan kỳ ngồi cạnh mĩ nữ tu vi Luyện Khí kỳ tầng 12-13 hoặc Trúc Cơ sơ kỳ theo quy tắc nơi này.","theLucLienQuan":[],"nguon":["@c0534"]},{"id":"vach-nui-da-ngoai-tinh-hai","name":"Vách núi đá (sào huyệt trao đổi Ngoại Tinh Hải)","cn":"","capDo":"khac","parentId":"ngoai-tinh-hai","blurb":"Nơi diễn ra hội trao đổi của các tu sĩ Kết Đan kỳ tại Ngoại Tinh Hải, có lão nhân trông cửa. Hàn Lập mang Văn Tư Nguyệt phá không rời khỏi nơi này.","detail":"Vách núi đá nơi Phạm phu nhân tổ chức hội trao đổi, cũng là nơi Hàn Lập trấn nhiếp quần tu Kết Đan kỳ. Có đại sảnh bên trong và lão nhân trông cửa canh gác bên ngoài.","theLucLienQuan":["Diệu Âm Môn"],"nguon":["@c0537"]},{"id":"hoang-dao-linh-khi-thua-thot","name":"Hoang đảo linh khí thưa thớt","cn":"","capDo":"khac","parentId":"ngoai-tinh-hai","blurb":"Hoang đảo mà Hàn Lập tìm được sau hai ngày phi hành cùng Văn Tư Nguyệt, linh khí thưa thớt.","detail":"Sau hai ngày rời vách núi đá, Hàn Lập tìm được hoang đảo này tại Ngoại Tinh Hải và hạ xuống cùng Văn Tư Nguyệt.","theLucLienQuan":[],"nguon":["@c0537"]},{"id":"noi-san-sinh-huyen-mong-thach","name":"Nơi sản sinh Huyễn Mộng Thạch","cn":"","capDo":"khac","parentId":"ngoai-tinh-hai","blurb":"Khu vực có yêu thú cấp năm–sáu sinh sống, thậm chí cấp bảy, nơi sản sinh Huyễn Mộng Thạch mà Diệu Âm Môn đã dò xét mấy năm.","detail":"Khu vực Diệu Âm Môn dò xét mấy năm, xác định có Huyễn Mộng Thạch nhưng bị đám yêu thú cấp cao (cấp năm, sáu, thậm chí bảy) canh giữ. Cần hợp lực nhiều tu sĩ Kết Đan kỳ mới có thể thanh trừ.","theLucLienQuan":[],"nguon":["@c0537"]},{"id":"dao-hoang-ngoai-tinh-hai","name":"Đảo hoang (Ngoại Tinh Hải)","capDo":"khac","parentId":"ngoai-tinh-hai","blurb":"Hòn đảo có vài ngọn núi lớn rộng mấy trăm trượng, cây cối xanh um. Hàn Lập khai phá động phủ dưới chân núi để an trí Văn Tư Nguyệt tu luyện.","detail":"Đảo hoang tại Ngoại Tinh Hải, có vài ngọn núi lớn. Hàn Lập dùng phi kiếm khai phá động phủ nhỏ dưới chân một ngọn núi (bằng nửa động phủ vụ hải, có phòng ngủ, mật thất, phòng luyện khí, dược viên), bố trí trận pháp lối vào, an trí Văn Tư Nguyệt ở đây.","theLucLienQuan":[],"nguon":["@c0538"]},{"id":"sao-huyet-liet-phong-thu","name":"Sào huyệt Liệt Phong Thú","cn":"","capDo":"khac","parentId":"tham-uyen","blurb":"Hòn đảo nhỏ tại phụ cận Thâm uyên hải vực, bên trong có động thiên nhiên khổng lồ chứa hồ nước nóng và Bạn Yêu Thảo đen.","detail":"Hòn đảo nhỏ nơi Liệt Phong Thú trú ngụ. Bên trong sườn núi đá có động khẩu bí mật rộng mấy chục trượng che bởi đá lớn. Qua đó là động thiên nhiên khổng lồ rộng hơn trăm trượng, cao hơn mười trượng, đỉnh thạch bích phát lục quang nhàn nhạt. Giữa động có hồ nước xanh tỏa sức nóng, sâu không thể dò, xung quanh mọc nhiều cây kỳ quái và Bạn Yêu Thảo đen.","theLucLienQuan":[],"nguon":["@c0539"]},{"id":"dong-phu-liet-phong-thu","name":"Động phủ Liệt Phong Thú","cn":"","capDo":"khac","parentId":"lan-hoa-dam","blurb":"Động phủ của Liệt Phong Thú nằm dưới đáy Lân Hỏa đàm, có cửa đá đen lớn với cấm chế bạch quang.","detail":"Nằm dưới đáy Lân Hỏa đàm. Cửa vào là cửa đá đen lớn có cấm chế bạch quang. Thông đạo bên trong gắn trân châu lớn lấy từ sò hến thông linh sống hàng ngàn năm, có công hiệu tị thủy ích hỏa. Đại sảnh trang hoàng san hô diễm lệ, bàn ghế ngọc trắng, bốn phía có tiểu đỉnh cổ xưa đốt hương đen tỏa mùi thơm.","theLucLienQuan":["Phong Hi (Liệt Phong Thú)"],"nguon":["@c0540"]},{"id":"mat-that-san-ho","name":"Mật thất san hô","cn":"","capDo":"khac","parentId":"sao-huyet-liet-phong-thu","blurb":"Mật thất bên trong tòa lầu san hô khổng lồ tại sào huyệt Liệt Phong Thú, nơi Hàn Lập bị giam để luyện hoá Bích Diễm Tửu.","detail":"Mật thất nằm sau bức vách san hô của tòa lầu khổng lồ tạo thành từ san hô, vách hồng quang hoa lấp loé. Rộng ba bốn mươi trượng, cao bảy tám trượng, bên trong chỉ có một ngọc tháp phát thanh quang. Vách tường đầy nốt nhỏ li ti giống ma điểm. Thần thức chạm vách đều bị bắn ngược, không có sơ hở. Phong Hi giam Hàn Lập tại đây để luyện hoá Bích Diễm Tửu, ước tính hơn nửa năm.","theLucLienQuan":["Bộ tộc Liệt Phong Thú"],"nguon":["@c0541"]},{"id":"co-dao-day-bien-loi-bang","name":"Cô đảo dưới đáy biển (di hài Lôi Bằng điểu)","cn":"","capDo":"khac","parentId":null,"blurb":"Cô đảo dưới đáy biển nơi Phong Hi phát hiện di hài Lôi Bằng điểu thượng cổ, chỉ còn bộ xương cánh bạc ẩn chứa lôi điện lực kinh người.","detail":"Phong Hi vài năm trước tu luyện dưới đáy biển, vô tình phát hiện cô đảo này. Trên đảo có di hài một con Lôi Bằng điểu thượng cổ khổng lồ đã hóa hình, chỉ còn lại bộ xương màu bạc.","theLucLienQuan":[],"nguon":["@c0543"]},{"id":"van-truong-hai","name":"Vạn trượng hải","cn":"","capDo":"hai-vuc","parentId":null,"blurb":"Chiến trường giữa yêu tộc và tu sĩ nhân loại, nơi Giao Long Nhất tộc cấp cao ra tay giúp phá thành trì nhân loại và giết hai tu sĩ Nguyên Anh kỳ.","detail":"Hải vực là chiến trường giữa phe yêu tộc và tu sĩ nhân loại. Giao Long Nhất tộc có yêu tộc cấp cao tham gia công kích, nhờ vậy phá được thành trì đối phương và giết hai tu sĩ Nguyên Anh kỳ nhân loại.","theLucLienQuan":["Giao Long Nhất tộc"],"nguon":["@c0543"]}]};
